# Primary VPC used to create the Private Hosted Zone
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "primary-vpc"
  }
}

# Secondary VPC to be associated with the existing Private Hosted Zone
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secondary-vpc"
  }
}

# The Route 53 Private Hosted Zone
# A private zone must be associated with at least one VPC at creation
resource "aws_route53_zone" "private" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.primary.id
  }

  tags = {
    Name = "private-hosted-zone"
  }
}

# Route 53 Hosted Zone Association
# This resource associates the secondary VPC with the hosted zone
resource "aws_route53_zone_association" "secondary_vpc" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}

