terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "main"
}

provider "aws" {
  region = "us-east-1"
  alias  = "us-east"
}

provider "aws" {
  region = "eu-central-1"
  alias  = "eu-central"
}

provider "aws" {
  region = "ap-southeast-1"
  alias  = "ap-southeast"
}

# Primary DB Instance in us-west-1
resource "aws_db_instance" "primary" {
  provider             = aws.main
  identifier           = "primary"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_name              = "mydb"
  username             = "admin"
  password             = "changeme123"
  skip_final_snapshot  = true
  backup_retention_period = 1 # Required for read replicas
  publicly_accessible  = true
}

# Replica 1 in us-east-1
resource "aws_db_instance" "replica_us_east" {
  provider               = aws.us-east
  identifier             = "replica_us_east"
  replicate_source_db    = aws_db_instance.primary.identifier
  instance_class         = "db.t3.micro"
  skip_final_snapshot    = true
  publicly_accessible    = true
}

# Replica 2 in eu-central-1
resource "aws_db_instance" "replica_eu_central" {
  provider               = aws.eu-central
  identifier             = "replica_eu_central"
  replicate_source_db    = aws_db_instance.primary.identifier
  instance_class         = "db.t3.micro"
  skip_final_snapshot    = true
  publicly_accessible    = true
}

# Replica 3 in ap-southeast-1
resource "aws_db_instance" "replica_ap_southeast" {
  provider               = aws.ap-southeast
  identifier             = "replica_ap_southeast"
  replicate_source_db    = aws_db_instance.primary.identifier
  instance_class         = "db.t3.micro"
  skip_final_snapshot    = true
  publicly_accessible    = true
}

# Route 53 Hosted Zone in us-west-1
resource "aws_route53_zone" "main" {
  provider = aws.main
  name     = "example.com"
}

# Weighted Route 53 Record for us-east-1 Replica
resource "aws_route53_record" "replica_us_east" {
  provider    = aws.main
  zone_id     = aws_route53_zone.main.zone_id
  name        = "replicas.example.com"
  type        = "CNAME"
  ttl         = "300"
  records     = [aws_db_instance.replica_us_east.address]

  set_identifier = "us-east"
  weighted_routing_policy {
    weight = 10
  }
}

# Weighted Route 53 Record for eu-central-1 Replica
resource "aws_route53_record" "replica_eu_central" {
  provider    = aws.main
  zone_id     = aws_route53_zone.main.zone_id
  name        = "replicas.example.com"
  type        = "CNAME"
  ttl         = "300"
  records     = [aws_db_instance.replica_eu_central.address]

  set_identifier = "eu-central"
  weighted_routing_policy {
    weight = 10
  }
}

# Weighted Route 53 Record for ap-southeast-1 Replica
resource "aws_route53_record" "replica_ap_southeast" {
  provider    = aws.main
  zone_id     = aws_route53_zone.main.zone_id
  name        = "replicas.example.com"
  type        = "CNAME"
  ttl         = "300"
  records     = [aws_db_instance.replica_ap_southeast.address]

  set_identifier = "ap-southeast"
  weighted_routing_policy {
    weight = 10
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
      configuration_aliases = [ aws.main, aws.us_east, aws.eu_central, aws.ap_southeast ]
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  alias = "main"
  region = "us-west-2" 

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "us_east"
  region = "us-east-1" # Example region for US East

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1" # Example region for EU Central

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "ap_southeast"
  region = "ap-southeast-1" # Example region for AP Southeast

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier = "master"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_us_east" {
  provider             = aws.us_east
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-us-east"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_eu_central" {
  provider             = aws.eu_central
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-eu-central"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider             = aws.ap_southeast
  replicate_source_db  = aws_db_instance.primary.arn

  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-ap-southeast"
  skip_final_snapshot  = true
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_us_east_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "us.east.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_us_east.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "eu.central.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_eu_central.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "ap.southeast.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_ap_southeast.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-ap-southeast"
}

