provider "aws" {
  region = "us-east-1"
}

# Variables for the DB Endpoints (to be passed in or replaced with actual values)
variable "primary_db_endpoint" {
  description = "The DNS endpoint of the primary DB instance"
  type        = string
  default     = "primary-db.example.com"
}

variable "replica1_db_endpoint" {
  description = "The DNS endpoint of replica-1"
  type        = string
  default     = "replica-1-db.example.com"
}

variable "replica2_db_endpoint" {
  description = "The DNS endpoint of replica-2"
  type        = string
  default     = "replica-2-db.example.com"
}

# Hosted Zone named "main"
resource "aws_route53_zone" "main" {
  name = "main.internal"
}

# Record for the Primary Instance
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary"
  type    = "CNAME"
  ttl     = "300"
  records = [var.primary_db_endpoint]
}

# Weighted Routing Configuration for Replicas
# Record for replica-1
resource "aws_route53_record" "replica_1" {
  zone_id          = aws_route53_zone.main.zone_id
  name             = "replicas"
  type             = "CNAME"
  set_identifier   = "replica-1"
  weighted_routing_policy {
    weight = 50
  }
  records = [var.replica1_db_endpoint]
}

# Record for replica-2
