# Provider for Global Resources (Route 53)
provider "aws" {
  region = "us-east-1"
  alias  = "global"
}

# Provider for US West Region
provider "aws" {
  region = "us-west-1"
  alias  = "west"
}

# Provider for EU Central Region
provider "aws" {
  region = "eu-central-1"
  alias  = "central"
}

# Data source to select a recent solution stack (e.g., Node.js on Linux 2)
data "aws_elastic_beanstalk_solution_stack" "nodejs" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2 v.* running Node.js"
}

# --- US West Resources ---

resource "aws_elastic_beanstalk_application" "app_west" {
  provider    = aws.west
  name        = "multi-region-app"
  description = "Application for US West"
}

resource "aws_elastic_beanstalk_environment" "us_west" {
  provider                = aws.west
  name                    = "us_west"
  application             = aws_elastic_beanstalk_application.app_west.name
  solution_stack_name     = data.aws_elastic_beanstalk_solution_stack.nodejs.name
  tier                    = "WebServerStandard"
  wait_for_ready_timeout  = "20m"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }
}

# --- EU Central Resources ---

resource "aws_elastic_beanstalk_application" "app_central" {
  provider    = aws.central
  name        = "multi-region-app"
  description = "Application for EU Central"
}

resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider                = aws.central
  name                    = "eu_central"
  application             = aws_elastic_beanstalk_application.app_central.name
  solution_stack_name     = data.aws_elastic_beanstalk_solution_stack.nodejs.name
  tier                    = "WebServerStandard"
  wait_for_ready_timeout  = "20m"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }
}

# --- Route 53 Resources ---

resource "aws_route53_zone" "main" {
  provider = aws.global
  name     = "example.com"
}

resource "aws_route53_record" "us_west" {
  provider = aws.global
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_elastic_beanstalk_environment.us_west.cname]

  latency_routing_policy {
    region = "us-west-1"
  }
}

resource "aws_route53_record" "eu_central" {
  provider = aws.global
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_elastic_beanstalk_environment.eu_central.cname]

  latency_routing_policy {
    region = "eu-central-1"
  }
}
