  identifier             = "mydb-instance"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "5.7"
  instance_class         = "db.t2.micro"
  db_name                = "my_db"
  username               = "admin"
  password               = "changeme123"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot    = false
  final_snapshot_identifier = "final-snapshot-termination"
}

# --- Database Snapshot ---
resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_instance_identifier = aws_db_instance.default.identifier
  db_snapshot_identifier = "pre-deployment-snapshot"

  depends_on = [aws_db_instance.default]
}

# --- Elastic Beanstalk Application ---
