resource "aws_route_table" "eb_public_rt" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }

  tags = {
    Name = "eb_public_rt"
  }
}

resource "aws_route_table_association" "eb_rta_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_public_rt.id
}

resource "aws_route_table_association" "eb_rta_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_public_rt.id
}

# Security Group
resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Security group for Elastic Beanstalk and RDS"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_env_sg"
  }
}

# DB Subnet Group (Required for RDS inside VPC)
resource "aws_db_subnet_group" "shared_rds_subnet_group" {
  name       = "shared_rds_subnet_group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "shared_rds_subnet_group"
  }
}

# RDS Instance
resource "aws_db_instance" "shared_rds" {
  identifier             = "shared_rds"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_encrypted      = false
  db_subnet_group_name   = aws_db_subnet_group.shared_rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.eb_env_sg.id]
  username               = "admin"
  password               = "changeme123"
  skip_final_snapshot    = true
  publicly_accessible    = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "eb_app"
  description = "Application for Elastic Beanstalk environments"
}

# Elastic Beanstalk Environment 1
resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  name                = "eb-env-1"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9"

  setting {
    namespace = "aws:ec2:vpc"
