}

resource "aws_iam_role_policy_attachment" "eb_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile1" {
  name = "eb_ec2_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

# RDS Database
resource "aws_db_instance" "default" {
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "5.7"
  instance_class         = "db.t3.micro"
  db_name                = "myapp_db"
  username               = "admin"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "default" {
  name        = "myapp"
  description = "My Application"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.default.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.0 running Python"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile1.name
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", aws_subnet.public[*].id)
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = join(",", aws_subnet.public[*].id)
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "EnvironmentVariables"
    value     = "{"RDS_HOSTNAME":"${aws_db_instance.default.endpoint}","RDS_DB_NAME":"${aws_db_instance.default.db_name}","RDS_USERNAME":"${aws_db_instance.default.username}","RDS_PASSWORD":"${random_password.db_password.result}"}"
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Route 53 Record to route to Elastic Beanstalk
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv.elb_zone_id
    evaluate_target_health = true
  }
}

