provider "aws" {
  region = "us-east-1"
}

# Variables for configuration
variable "app_name" {
  description = "The name of the Elastic Beanstalk Application"
  type        = string
  default     = "my-go-app"
}

variable "env_name" {
  description = "The name of the Elastic Beanstalk Environment"
  type        = string
  default     = "my-go-app-env"
}

variable "s3_bucket" {
  description = "The S3 bucket where the application source code is stored"
  type        = string
}

variable "s3_key" {
  description = "The S3 key (path) to the application source code zip file"
  type        = string
}

variable "instance_type" {
  description = "EC2 instance type for the environment"
  type        = string
  default     = "t3.micro"
}

# --- IAM Resources ---

# IAM Role for EC2 Instances
resource "aws_iam_role" "ec2_role" {
  name = "${var.app_name}-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_attach_web_tier" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "ec2_attach_worker_tier" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "${var.app_name}-ec2-profile"
  role = aws_iam_role.ec2_role.name
}

# IAM Role for Elastic Beanstalk Service
resource "aws_iam_role" "service_role" {
  name = "${var.app_name}-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "service_attach_enhanced_health" {
  role       = aws_iam_role.service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
}

# --- Elastic Beanstalk Resources ---

# Fetch the latest Amazon Linux 2 Go solution stack
data "aws_elastic_beanstalk_solution_stack" "go_linux2" {
  name_regex = "^64bit Amazon Linux 2 .* Go$"
  most_recent = true
}

resource "aws_elastic_beanstalk_application" "app" {
  name        = var.app_name
  description = "Go Application managed by Terraform"
}

resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "v1-${timestamp()}" # Append timestamp to ensure unique versions
  application = aws_elastic_beanstalk_application.app.name
  description = "Application version v1"
  bucket      = var.s3_bucket
  key         = var.s3_key

  # Ensure the app exists before creating version
  depends_on = [
    aws_elastic_beanstalk_application.app
  ]
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = var.env_name
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.go_linux2.name
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = var.instance_type
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.service_role.name
  }

  # Setting for health check (Go usually runs on port 5000 by default if not configured otherwise)
  setting {
    namespace = "aws:elasticbeanstalk:application"
    name      = "Application Healthcheck URL"
    value     = "/"
  }
}
```

