provider "aws" {
  region = "us-east-1"
}

# Resource: ECR Repository
# Stores the container image for the web application. 
# This allows the web app to be built in any language (Node.js, Python, Go, etc.) as long as it is containerized.
resource "aws_ecr_repository" "web_app_repo" {
  name                 = "web-app-repo"
  image_tag_mutability = "MUTABLE"

  image_scanning_configuration {
    scan_on_push = true
  }
}

# Resource: IAM Role for App Runner
# Grants App Runner permissions to pull the image from ECR and write logs to CloudWatch.
resource "aws_iam_role" "apprunner_service_role" {
  name = "approuter-web-app-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "build.apprunner.amazonaws.com"
        }
      },
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "tasks.apprunner.amazonaws.com"
        }
      }
    ]
  })
}

# Resource: IAM Policy Attachment (ECR Access)
# Allows the service to read from the created ECR repository.
resource "aws_iam_role_policy_attachment" "apprunner_ecr_policy" {
  role       = aws_iam_role.apprunner_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSAppRunnerServicePolicyForECRAccess"
}

# Resource: IAM Policy Attachment (CloudWatch Logs)
# Allows the service to stream logs to CloudWatch.
resource "aws_iam_role_policy_attachment" "apprunner_logs_policy" {
  role       = aws_iam_role.apprunner_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSAppRunnerServicePolicyForCloudWatchLogs"
}

# Resource: App Runner Service
# The main compute resource. It automatically deploys the container, 
# manages load balancing, and automatically scales based on incoming traffic.
resource "aws_apprunner_service" "web_app_service" {
  service_name = "auto-scale-web-app-service"

  instance_configuration {
    cpu    = "256"
    memory = "512"
    # Reference to the IAM role for instance-level permissions (e.g., accessing other AWS services)
    instance_role_arn = aws_iam_role.apprunner_service_role.arn
  }

  source_configuration {
    image_repository {
      image_configuration {
        port = "80"
        runtime_environment_variables = {
          PORT           = "80"
          NODE_ENV       = "production"
        }
      }
      # Assumes an image tagged 'latest' exists in the repository
      image_identifier      = "${aws_ecr_repository.web_app_repo.repository_url}:latest"
      image_repository_type = "ECR"
    }
    # Role used to authenticate with ECR to pull the image
    authentication_configuration {
      access_role_arn = aws_iam_role.apprunner_service_role.arn
    }
    # Set to false to prevent immediate deployment attempts before an image is pushed
    auto_deployments_enabled = false 
  }

  tags = {
    Name        = "WebAppService"
    Environment = "Production"
  }
}

