provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "example_codebuild_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Attach managed policies for basic CodeBuild operations (Logs, S3, etc.)
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# Source Credential for GitHub (OAuth Token)
# Note: In a real environment, pass the token via a variable or environment variable
resource "aws_codebuild_source_credential" "github_credential" {
  auth_type   = "OAUTH"
  server_type = "GITHUB"
  token       = var.github_token # Assumes variable "github_token" is defined
}

# CodeBuild Project
resource "aws_codebuild_project" "example_project" {
  name          = "example-project"
  description   = "Example CodeBuild project with GitHub source and caching"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"
  queued_timeout = "5"

  artifacts {
    type     = "S3"
    location = "my-build-artifacts-bucket"
    name     = "build-output.zip"
    packaging = "ZIP"
  }

  cache {
    type     = "S3"
    location = "my-build-cache-bucket"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "TERRAFORM_VERSION"
      value = "1.0.0"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/my-org/my-repo.git"
    git_clone_depth = 1

    auth {
      type     = "OAUTH"
      resource = aws_codebuild_source_credential.github_credential.arn
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "aws/codebuild/example-project"
      stream_name = "build-logs"
    }
    s3_logs {
      status   = "ENABLED"
      location = "my-build-logs-bucket/logs/"
    }
  }
}

variable "github_token" {
  description = "GitHub OAuth token for authentication"
  type        = string
  sensitive   = true
}

