provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# IAM Role for CodeBuild
# -----------------------------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Policy granting basic permissions for CodeBuild (Logs, S3, etc.)
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-example-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = [
          "arn:aws:logs:*:*:log-group:/aws/codebuild/*",
          "arn:aws:logs:*:*:log-group:/aws/codebuild/*:*"
        ]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = [
          "arn:aws:s3:::codebuild-artifacts-bucket-example/*",
          "arn:aws:s3:::codebuild-artifacts-bucket-example"
        ]
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# CodeBuild Project
# -----------------------------------------------------------------------------
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example project with primary and secondary sources"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"
  queued_timeout = "480"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "TERRAFORM_VERSION"
      value = "1.0.0"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "aws/codebuild/example-project"
      stream_name = "build-logs"
    }
    s3_logs {
      status = "DISABLED"
    }
  }

  # Primary Source
  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    report_build_status = true
  }

  # Secondary Source Configuration
  secondary_sources {
    type            = "GITHUB"
    location        = "https://github.com/example/secondary-repo.git"
    source_identifier = "secondary_source_code"
    git_clone_depth = 1
  }

  # Pin the secondary source to a specific version (branch/ref)
  secondary_source_version {
    source_identifier = "secondary_source_code"
    source_version    = "main"
  }
}

