      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Attach Policies to the Role
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example project with secondary sources and artifacts"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Secondary Artifacts
  secondary_artifacts {
    artifact_identifier = "secondary-artifact-1"
    type               = "S3"
    location           = aws_s3_bucket.codebuild_bucket.bucket
    name               = "secondary-1.zip"
    path               = "secondary-artifacts-1"
    namespace_type     = "BUILD_ID"
    packaging          = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "secondary-artifact-2"
    type               = "S3"
    location           = aws_s3_bucket.codebuild_bucket.bucket
    name               = "secondary-2.zip"
    path               = "secondary-artifacts-2"
    namespace_type     = "BUILD_ID"
    packaging          = "NONE"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # Environment Variables
    environment_variables {
      name  = "TERRAFORM_VERSION"
      value = "1.0.0"
    }

    environment_variables {
      name  = "ENVIRONMENT"
      value = "dev"
      type  = "PLAINTEXT"
    }
