    location          = "${aws_s3_bucket.codebuild_bucket.bucket}/source-2.zip"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "aws-codebuild-logs"
      stream_name = "example-project-stream"
    }
  }
}

