resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex-v2-bot-policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# The Lex V2 Bot
resource "aws_lexv2models_bot" "example_bot" {
  name                        = "ExampleChatbot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  # Required test alias settings for bot creation
  test_bot_alias_settings {
    bot_alias_name = "TestAlias"
    bot_alias_locale_settings {
      locale_id = "en_US"
      enabled   = true
    }
  }
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                   = aws_lexv2models_bot.example_bot.id
  bot_version              = "DRAFT"
  locale_id                = "en_US"
  nlu_confidence_threshold = 0.40
}

# Intent: Greeting
resource "aws_lexv2models_intent" "greeting" {
  bot_id      = aws_lexv2models_bot.example_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "Greeting"

  sample_utterances {
    utterance = "Hi"
  }
  sample_utterances {
    utterance = "Hello"
  }
  sample_utterances {
    utterance = "Good morning"
  }

  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! How can I help you today?"
          }
        }
      }
    }
  }
}

# Bot Alias (Points to DRAFT for immediate testing)
resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.example_bot.id
  bot_alias_name   = "Production"
  bot_version      = "DRAFT"
  bot_alias_locale_settings {
    locale_id = "en_US"
    enabled   = true
  }
}

