  locale_id   = "en_US"
  name        = "PizzaSize"

  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }

  slot_type_values {
    sample_value { value = "Small" }
    synonyms { value = "S" }
  }
  slot_type_values {
    sample_value { value = "Medium" }
    synonyms { value = "M" }
  }
  slot_type_values {
    sample_value { value = "Large" }
    synonyms { value = "L" }
  }
}

# Slot Type: Pizza Crust
resource "aws_lexv2models_slot_type" "pizza_crust" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "PizzaCrust"

  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }

  slot_type_values {
    sample_value { value = "Thin" }
  }
  slot_type_values {
    sample_value { value = "Thick" }
  }
  slot_type_values {
    sample_value { value = "Stuffed" }
  }
