    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order a pizza"
  }
  sample_utterances {
    utterance = "Can I get a {Size} pizza"
  }
  sample_utterances {
    utterance = "I'd like a {Crust} crust pizza"
  }

  # Closing Summary Statement
  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Thanks for ordering! I have placed an order for a {Size} pizza with {Crust} crust."
          }
        }
      }
    }
  }

  # Slot: Size
  slot_priorities {
    priority = 1
    slot_name = "Size"
  }
  slots {
    name           = "Size"
    description    = "Size of the pizza"
    slot_type_id   = aws_lexv2models_slot_type.pizza_size.slot_type_id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_groups {
          message {
            plain_text_message {
              value = "What size pizza would you like? We have Small, Medium, or Large."
            }
          }
        }
        max_retries      = 2
        allow_interrupt  = true
      }
    }
  }

  # Slot: Crust
  slot_priorities {
    priority = 2
    slot_name = "Crust"
  }
  slots {
    name           = "Crust"
    description    = "Type of crust"
    slot_type_id   = aws_lexv2models_slot_type.pizza_crust.slot_type_id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_groups {
          message {
            plain_text_message {
              value = "What type of crust would you prefer? Options are Thin, Thick, or Stuffed."
            }
          }
        }
        max_retries      = 2
        allow_interrupt  = true
      }
    }
  }

  dialog_code_hook {
    enabled = false
  }

  fulfillment_code_hook {
    enabled = false
  }
}
```

