provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex_pizza_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexBotPolicy"
}

# Slot Type for Pizza Types
resource "aws_lexv2models_slot_type" "pizza_type" {
  name                 = "PizzaType"
  description          = "Types of pizza available"
  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }
  slot_type_values {
    name = "Pepperoni"
    sample_value {
      value = "Pepperoni"
    }
  }
  slot_type_values {
    name = "Margherita"
    sample_value {
      value = "Margherita"
    }
  }
  slot_type_values {
    name = "Hawaiian"
    sample_value {
      value = "Hawaiian"
    }
  }
  slot_type_values {
    name = "Veggie"
    sample_value {
      value = "Veggie"
    }
  }
}

# Intent 1: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  name                 = "OrderPizza"
  description          = "Intent to order a pizza"
  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Can I get a {PizzaType}"
  }
  sample_utterances {
    utterance = "Order pizza for me"
  }

  dialog_code_hook {
    enabled = true
  }

  fulfillment_code_hook {
    enabled = true
  }

  slot_details {
    slot_name = "PizzaType"
    slot_type_id = aws_lexv2models_slot_type.pizza_type.id
    value elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What type of pizza would you like to order? We have Pepperoni, Margherita, Hawaiian, or Veggie."
            }
          }
        }
      }
    }
  }
}

# Intent 2: CheckStatus
resource "aws_lexv2models_intent" "check_status" {
  name                 = "CheckStatus"
  description          = "Check the status of an existing order"
  sample_utterances {
    utterance = "Where is my order"
  }
  sample_utterances {
    utterance = "Check status of order {OrderId}"
  }
  sample_utterances {
    utterance = "Has my pizza been delivered"
  }

  dialog_code_hook {
    enabled = true
  }

  slot_details {
    slot_name = "OrderId"
    slot_type_id = "Amazon.AlphaNumeric"
    value elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "Please provide your Order ID to check the status."
            }
          }
        }
      }
    }
  }
}

# Intent 3: GetMenu
resource "aws_lexv2models_intent" "get_menu" {
  name                 = "GetMenu"
  description          = "List the items available on the menu"
  sample_utterances {
    utterance = "Show me the menu"
  }
  sample_utterances {
    utterance = "What do you have"
  }
  sample_utterances {
    utterance = "What pizzas can I order"
  }

  dialog_code_hook {
    enabled = true
  }

  fulfillment_code_hook {
    enabled = true
  }
}

# Intent 4: CancelOrder
resource "aws_lexv2models_intent" "cancel_order" {
  name                 = "CancelOrder"
  description          = "Cancel a recent order"
  sample_utterances {
    utterance = "Cancel my order"
  }
  sample_utterances {
    utterance = "I want to cancel order {OrderId}"
  }
  sample_utterances {
    utterance = "Stop my pizza delivery"
  }

  dialog_code_hook {
    enabled = true
  }

  slot_details {
    slot_name = "OrderId"
    slot_type_id = "Amazon.AlphaNumeric"
    value elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What is the Order ID you wish to cancel?"
            }
          }
        }
      }
    }
  }
}

# Intent 5: GetSpecials
resource "aws_lexv2models_intent" "get_specials" {
  name                 = "GetSpecials"
  description          = "Ask about current deals and specials"
  sample_utterances {
    utterance = "Do you have any specials"
  }
  sample_utterances {
    utterance = "What are the deals today"
  }
  sample_utterances {
    utterance = "Are there any discounts"
  }

  dialog_code_hook {
    enabled = true
  }

  fulfillment_code_hook {
    enabled = true
  }
}

# Lex Bot Resource
resource "aws_lexv2models_bot" "pizza_ordering_bot" {
  name                        = "PizzaOrderingBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  bot_tags {
    key   = "Environment"
    value = "Production"
  }
}

# Bot Locale
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                    = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version               = "DRAFT"
  locale_id                 = "en_US"
  nlu_confidence_threshold = 0.40
}

# Bot Version (Links Intents)
resource "aws_lexv2models_bot_version" "v1" {
  bot_id = aws_lexv2models_bot.pizza_ordering_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      bot_version_locale_details = {
        source_bot_version = "DRAFT"
      }
    }
  }
  depends_on = [
    aws_lexv2models_bot_locale.en_us
  ]
}

# Bot Alias
resource "aws_lexv2models_bot_alias" "prod_alias" {
  bot_id           = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = aws_lexv2models_bot_locale.en_us.locale_id
    enabled                      = true
  }
  depends_on = [
    aws_lexv2models_bot_version.v1
  ]
}

# Linking Intents to the Locale (Required for V2 logic)
# Note: In Lex V2, intents are compiled into the version. 
# We create a resource to update the draft version with the intents before publishing v1.
resource "aws_lexv2models_bot_version" "draft_with_intents" {
  # This resource illustrates linking intents to the bot structure for deployment
  # In a real CI/CD flow, you might update the DRAFT locale directly.
  # For this static config, we ensure the intents are created.

  bot_id = aws_lexv2models_bot.pizza_ordering_bot.id

  # Note: Terraform doesn't explicitly create a "link" resource for intents to draft outside of version creation or specific API calls.
  # The intents defined above are available to be used. 
  # We will rely on the 'OrderPizza' intent and others being defined in the cloud.
}

