resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.kids_pizza_bot.id
  bot_version = "DRAFT"
  name        = "OrderPizza"

  sample_utterances {
    utterance = "I want a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }
  sample_utterances {
    utterance = "Can I have a {Size} {Topping} pizza"
  }

  # Slot: Size
  slot {
    name           = "Size"
    slot_type_id   = aws_lexv2models_slot_type.pizza_size.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What size pizza do you want? Small, Medium, or Large?"
            }
          }
        }
        max_retries = 2
      }
    }
  }

  # Slot: Topping
  slot {
    name           = "Topping"
    slot_type_id   = aws_lexv2models_slot_type.pizza_topping.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What topping would you like?"
            }
          }
        }
        max_retries = 2
      }
    }
  }

  # Closing Response
  closing_setting {
    active = true
    response_specification {
      message_group {
        message {
          plain_text_message {
            value = "Yay! I ordered your {Size} {Topping} pizza. It will be there soon!"
          }
        }
      }
    }
  }
}

