provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# IAM Roles
# -----------------------------------------------------------------------------

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "pizza_order_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "pizza_lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow Lex to invoke Lambda and write to CloudWatch
resource "aws_iam_role_policy" "lex_policy" {
  name = "lex_bot_policy"
  role = aws_iam_role.lex_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "lambda:InvokeFunction"
        ]
        Resource = aws_lambda_function.pizza_order.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "polly:SynthesizeSpeech"
        ]
        Resource = "*"
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# Lambda Function
# -----------------------------------------------------------------------------

# Data source to archive the Lambda code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "${path.module}/lambda_function.py"
  output_path = "${path.module}/pizza_order.zip"
}

# Create the dummy Lambda code file locally
resource "local_file" "lambda_source" {
  content = <<-EOF
import json

def lambda_handler(event, context):
    session_state = event['sessionState']
    intent = session_state['intent']['name']
    slots = session_state['intent']['slots']

    pizza_size = slots.get('PizzaSize', {}).get('value', 'Unknown')

    response = {
        "sessionState": {
            "dialogAction": {
                "type": "Close"
            },
            "intent": {
                "name": intent,
                "state": "Fulfilled"
            }
        },
        "messages": [
            {
                "contentType": "PlainText",
                "content": f"Order received! Getting started on your {pizza_size} pizza."
            }
        ]
    }
    return response
EOF
  filename = "${path.module}/lambda_function.py"
}

resource "aws_lambda_function" "pizza_order" {
  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  function_name    = "pizza_order_function"
  role             = aws_iam_role.lambda_role.arn
  handler          = "lambda_function.lambda_handler"
  runtime          = "python3.9"

  depends_on = [
    local_file.lambda_source
  ]
}

# Permission for Lex to invoke the Lambda
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = "${aws_lex_bot.pizza_bot.arn}/intent/OrderPizza/*" # Simplified ARN for intent hook
}

# -----------------------------------------------------------------------------
# Lex V2 Resources
# -----------------------------------------------------------------------------

# Custom Slot Type for Pizza Size
resource "aws_lex_slot_type" "pizza_size" {
  name           = "PizzaSize"
  description    = "Size of the pizza"
  value_selection_strategy = "ORIGINAL_VALUE"

  slot_type_values {
    name = "Small"
    sample_value {
      value = "Small"
    }
  }
  slot_type_values {
    name = "Medium"
    sample_value {
      value = "Medium"
    }
  }
  slot_type_values {
    name = "Large"
    sample_value {
      value = "Large"
    }
  }
}

# The Bot Container
resource "aws_lex_bot" "pizza_bot" {
  name           = "PizzaOrderBot"
  role_arn       = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type = "Bot"

  # Bot must have at least one locale to be created, but we define it explicitly below.
  # We add a lifecycle ignore to handle the complex versioning/dependency chain if needed
  # but standard dependencies work well here.
}

# The Bot Locale (en_US)
resource "aws_lex_bot_locale" "en_us" {
  bot_id    = aws_lex_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id = "en_US"
  nlu_confidence_threshold = 0.40

  # Define the Intent inside the Locale
  intents {
    name = "OrderPizza"
    description = "Orders a pizza"

    sample_utterances {
      utterance = "Order a pizza"
    }
    sample_utterances {
      utterance = "I want a {PizzaSize} pizza"
    }
    sample_utterances {
      utterance = "Get me a pizza"
    }

    # Configure the Lambda Fulfillment Hook
    fulfillment_code_hook {
      enabled = true
      post_fulfillment_hook_specification = {
        timeout_in_millis = 5000
      }
    }

    closing_setting {
      active = true
      response {
        message_group {
          message {
            plain_text_message {
              value = "Thanks for your order!"
            }
          }
        }
      }
    }

    # Define Slots
    slots {
      name = "PizzaSize"
      description = "The size of the pizza"
      slot_type_id = aws_lex_slot_type.pizza_size.id
      value_elicitation_setting {
        slot_constraint = "Required"
        default_value_specification {
          default_value {
            value = "Medium"
          }
        }
        prompt_specification {
          message_group {
            message {
              plain_text_message {
                value = "What size pizza would you like? Small, Medium, or Large?"
              }
            }
          }
          max_retries = 2
          allow_interrupt = true
        }
      }
    }
  }
}

# Create a Version (immutable snapshot of the DRAFT)
resource "aws_lex_bot_version" "v1" {
  bot_id = aws_lex_bot.pizza_bot.id
  locale_specification = {
    (aws_lex_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [
    aws_lex_bot_locale.en_us
  ]
}

# Create an Alias to point to the Version
resource "aws_lex_bot_alias" "production" {
  bot_id           = aws_lex_bot.pizza_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lex_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = aws_lex_bot_locale.en_us.locale_id
    enabled                      = true
  }

  depends_on = [
    aws_lex_bot_version.v1
  ]
}

