extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# 1. Create the Kinesis Data Stream (Input Source)
resource "aws_kinesis_stream" "input_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# 2. Create IAM Role for the Analytics Application
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach Policy to allow reading from the Kinesis Stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-read-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards",
          "kinesis:SubscribeToShard"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      }
    ]
  })
}

# 4. Create the Kinesis Data Analytics Application (V2)
resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "example-analytics-app"
  runtime_environment    = "SQL-1_0"
  description            = "Simple Kinesis Data Analytics application using SQL"
  service_execution_role = aws_iam_role.analytics_role.arn

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_streams {
      resource_arn = aws_kinesis_stream.input_stream.arn
    }

    # Define the schema for the incoming data (assuming JSON)
    schema {
      record_format {
        record_format_type = "JSON"
        mapping_parameters {
          json_mapping_parameters {
            record_row_path = "$"
          }
        }
      }
    }
  }
}

