terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create an IAM Role for the Kinesis Data Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-v2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the role allowing access to Kinesis, CloudWatch, and S3
resource "aws_iam_role_policy_attachment" "kinesis_analytics_policy" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# Create a CloudWatch Log Group for application logs
resource "aws_cloudwatch_log_group" "kinesis_analytics_log_group" {
  name              = "/aws/kinesis-analytics/MyFlinkApp"
  retention_in_days = 7
}

# Create the Kinesis Data Analytics V2 Application
resource "aws_kinesisanalyticsv2_application" "flink_app" {
  name                   = "my-flink-application"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    # Configure Flink application settings (Checkpoints, Monitoring, Parallelism)
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"

        metrics_namespace = "MyFlinkApp/KDA"
        log_streamARNs    = ["${aws_cloudwatch_log_group.kinesis_analytics_log_group.arn}:stream"]
      }

      parallelism_configuration {
        configuration_type = "CUSTOM"
        parallelism        = 1
        auto_scaling_enabled = false
      }
    }

    # Configure Application Code (Placeholder)
    # In a real scenario, you would point to an S3 bucket containing your Flink JAR or code
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.code_bucket.arn
          file_key   = "my-flink-app.jar"
          # object_version is optional
        }
      }
      code_content_type = "ZIPFILE"
    }

    # Environment properties for the application
    environment_properties {
      property_groups {
        property_group_id = "FlinkApplicationProperties"
        properties = {
          InputStreamName   = "ExampleInputStream"
          OutputStreamName  = "ExampleOutputStream"
          Region            = "us-east-1"
        }
      }
    }
  }
}

# Supporting Resource: S3 Bucket for code storage (Required for the application config)
resource "aws_s3_bucket" "code_bucket" {
  bucket = "my-kda-flink-code-bucket-12345"
}

resource "aws_s3_bucket_versioning" "code_bucket_versioning" {
  bucket = aws_s3_bucket.code_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

