provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for the Firehose Destination
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-extended-s3-firehose-bucket"
}

# IAM Role for Firehose to assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy granting Firehose permissions to S3 and CloudWatch Logs
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kinesis Data Firehose Delivery Stream with Extended S3 and Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "my-firehose-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/"

    # Enable Dynamic Partitioning
    dynamic_partitioning {
      enabled = true
    }

    # Optional: Buffering hints
    buffer_size     = 5
    buffer_interval = 300
  }
}

