terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Configuration for Redshift
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-redshift-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "firehose-redshift-subnet"
  }
}

resource "aws_redshift_subnet_group" "main" {
  name       = "firehose-redshift-subnet-group"
  subnet_ids = [aws_subnet.main.id]

  tags = {
    Name = "firehose-redshift-subnet-group"
  }
}

resource "aws_security_group" "redshift" {
  name   = "firehose-redshift-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "firehose-redshift-sg"
  }
}

# 2. S3 Bucket (Required for Redshift delivery as intermediate storage)
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-redshift-bucket-123456"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket]
  bucket     = aws_s3_bucket.firehose_bucket.id
  acl        = "private"
}

# 3. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_redshift_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary policies for S3 and Redshift access
resource "aws_iam_role_policy_attachment" "firehose_s3" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "firehose_redshift" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRedshiftAllCommands"
}

# 4. Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "tf-firehose-cluster"
  database_name       = "dev"
  master_username     = "admin"
  master_password     = "Test12345678" # Note: Use variables or Secrets Manager in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift.id]
  skip_final_snapshot = true

  depends_on = [aws_iam_role_policy_attachment.firehose_redshift]
}

# 5. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "tf-firehose-redshift-stream"
  destination = "redshift"

  # Configuration for the Redshift destination
  redshift_configuration {
    cluster_jdbcurl = "jdbc:redshift://${aws_redshift_cluster.main.endpoint}/${aws_redshift_cluster.main.database_name}"
    username        = aws_redshift_cluster.main.master_username
    password        = aws_redshift_cluster.main.master_password
    data_table_name = "firehose_table"
    copy_options    = "delimiter ','"

    role_arn = aws_iam_role.firehose_role.arn

    # S3 configuration for the Redshift COPY command source (intermediate storage)
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_bucket.arn
      prefix             = "redshift/"
      buffer_size        = 5
      buffer_interval    = 300
    }
  }

  # Note: s3_configuration at the top level is not used for Redshift destination logic 
  # (it uses the one inside redshift_configuration), but typically required for backup.
  # We will rely on the s3_configuration block inside redshift_configuration for the staging area.
  # We will explicitly set backup to disabled to simplify, or we can configure s3_backup_configuration.

  # Explicitly disable cloudwatch logging to keep it minimal
  # depends_on = [aws_redshift_cluster.main] # Ensure Redshift exists before creating stream
}

