provider "aws" {
  region = "us-east-1"
}

# Variables for specific Elasticsearch details
variable "es_domain_arn" {
  description = "The ARN of the Elasticsearch domain"
  type        = string
  default     = "" # Replace with actual ARN or pass via var
}

variable "es_index_name" {
  description = "The Elasticsearch index name"
  type        = string
  default     = "firehose-index"
}

# 1. S3 Bucket for Backup
resource "aws_s3_bucket" "firehose_backup_bucket" {
  bucket = "my-firehose-es-backup-bucket"
}

resource "aws_s3_bucket_ownership_controls" "firehose_backup_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_backup_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_backup_bucket.id
  acl        = "private"
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy allowing Firehose to write to ES and S3
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup_bucket.arn,
          "${aws_s3_bucket.firehose_backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = "${var.es_domain_arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeDomain",
          "es:DescribeDomainConfig"
        ]
        Resource = var.es_domain_arn
      }
    ]
  })
}

# 3. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
  name        = "terraform-firehose-es-stream"
  destination = "elasticsearch"

  # Elasticsearch Configuration
  elasticsearch_configuration {
    domain_arn = var.es_domain_arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = var.es_index_name

    # Backup failed documents to S3
    s3_backup_mode = "FailedDocumentsOnly"

    # Optional: Buffering hints and retry duration
    buffering_interval = 60
    buffering_size     = 5
    retry_duration     = 300
  }

  # S3 Configuration (Required for source/backup)
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup_bucket.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  # Explicit dependency to ensure IAM role and policy are ready
  depends_on = [aws_iam_role_policy.firehose_policy]
}

