resource "aws_iam_role" "firehose_role" {
  name = "firehose_splunk_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_splunk_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup_bucket.arn,
          "${aws_s3_bucket.firehose_backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "splunk-delivery-stream"
  destination = "splunk"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup_bucket.arn
    prefix             = "splunk-backup/"
    buffer_size        = 5
    buffer_interval    = 300
  }

  splunk_configuration {
    hec_endpoint                = "https://http-inputs-myhost.splunkcloud.com:443"
    hec_token                   = var.splunk_hec_token
    hec_acknowledgment_timeout_in_seconds = 600
    s3_backup_mode              = "FailedEventsOnly"
    retry_duration              = 60
  }

  server_side_encryption {
    enabled  = true
    key_type = "AWS_OWNED_CMK"
  }
}
