# Resource: S3 Bucket for Backup
# Kinesis Firehose requires an S3 bucket to backup data that fails to be delivered to the HTTP endpoint.
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-http-endpoint-backup-bucket"
}

resource "aws_s3_bucket_ownership_controls" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_backup" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup]
  bucket     = aws_s3_bucket.firehose_backup.id
  acl        = "private"
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Resource: IAM Role for Firehose
# Firehose assumes this role to write to the backup S3 bucket.
resource "aws_iam_role" "firehose_role" {
  name = "firehose_http_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Resource: IAM Policy for Firehose
# Grants access to the specific S3 bucket created above.
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_access"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      }
    ]
  })
}

# Resource: Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "http_stream" {
  name        = "new-relic-http-stream"
  destination = "http_endpoint"

  # HTTP Endpoint Configuration (e.g., New Relic)
  http_endpoint_configuration {
    name               = "NewRelicEndpoint"
    url                = var.http_endpoint_url
    access_key         = var.http_endpoint_access_key

    # Content transformation (optional)
    # processing_configuration { ... }

    # S3 Configuration is required even for HTTP endpoints for backup purposes
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      prefix             = "http-backup/"
      error_output_prefix = "errors/"

      # Buffering hints
      buffering_size     = 5
      buffering_interval = 300
    }

    # Retry options
    retry_duration = 60

    # S3 Backup Mode
    # "FailedDataOnly" is recommended to save costs, "AllData" backs up everything.
    s3_backup_mode = "FailedDataOnly"
  }

  # Tags
  tags = {
    Environment = "Production"
    Purpose     = "NewRelicLogIngestion"
  }
}

# Variables Definition
variable "http_endpoint_url" {
  description = "The URL of the HTTP Endpoint (e.g., New Relic Log API)"
  type        = string
  sensitive   = true
  # Example default for New Relic: https://log-api.newrelic.com/log/v1
}

variable "http_endpoint_access_key" {
  description = "The access key for the HTTP Endpoint"
  type        = string
  sensitive   = true
}

