provider "aws" {
  region = "us-east-1"
}

# 1. Create the Kinesis Data Stream (Input source)
resource "aws_kinesis_stream" "example_stream" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# 2. Create IAM Role for Kinesis Data Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Create IAM Policy to allow reading from the Kinesis Stream
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-read-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.example_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:ListStreams"
        ]
        Resource = "*"
      }
    ]
  })
}

# 4. Create Kinesis Data Analytics Application
resource "aws_kinesisanalyticsv2_application" "example_app" {
  name                   = "example-analytics-application"
  runtime_environment    = "FLINK-1_15" # Using Flink as the modern standard
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  inputs {
    name_prefix = "SOURCE_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.example_stream.arn
    }

    # Schema definition for the input stream
    schema {
      record_format {
        record_format_type = "JSON"
      }

      record_encoding = "UTF-8"

      record_columns {
        name     = "data"
        mapping  = "$.data"
        sql_type = "VARCHAR(200)"
      }
    }
  }
}

