# IAM Role for the Kinesis Data Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-v2-role-${random_integer.suffix.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Policy attachment to allow reading from and writing to Kinesis Streams
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.output.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesisanalytics:DescribeApplication",
          "kinesisanalytics:ListApplications",
          "kinesisanalytics:ListApplicationVersions",
          "kinesisanalytics:CreateApplicationVersion",
          "kinesisanalytics:DeleteApplicationVersion",
          "kinesisanalytics:DescribeApplicationVersion",
          "kinesisanalytics:DiscoverInputSchema",
          "kinesisanalytics:ListTagsForResource",
          "kinesisanalytics:AddApplicationCloudWatchLoggingOption",
          "kinesisanalytics:DeleteApplicationCloudWatchLoggingOption",
          "kinesisanalytics:DescribeApplicationCloudWatchLoggingOption",
          "kinesisanalytics:DescribeApplicationOperation",
          "kinesisanalytics:DescribeApplicationSnapshot",
          "kinesisanalytics:ListApplicationSnapshots",
          "kinesisanalytics:StartApplication",
          "kinesisanalytics:StopApplication",
          "kinesisanalytics:UpdateApplication"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Input Kinesis Data Stream
resource "aws_kinesis_stream" "input" {
  name             = "kinesis-analytics-input-${random_integer.suffix.id}"
  shard_count      = 1
  retention_period = 24
}

# Output Kinesis Data Stream
resource "aws_kinesis_stream" "output" {
  name             = "kinesis-analytics-output-${random_integer.suffix.id}"
  shard_count      = 1
  retention_period = 24
}

# Kinesis Data Analytics V2 Application (SQL-based)
resource "aws_kinesisanalyticsv2_application" "sql_app" {
  name                   = "kinesis-analytics-sql-app-${random_integer.suffix.id}"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"
        kinesis_stream_input {
          resource_arn = aws_kinesis_stream.input.arn
        }
        input_schema {
          record_format {
            record_format_type = "JSON"
          }
          record_encoding = "UTF-8"
          record_columns {
            name = "sensor_id"
            mapping = "$.sensor_id"
            sql_type = "VARCHAR(16)"
          }
          record_columns {
            name = "temperature"
            mapping = "$.temperature"
            sql_type = "DOUBLE"
          }
        }
      }

      output {
        name = "DESTINATION_SQL_STREAM"
        kinesis_stream_output {
          resource_arn = aws_kinesis_stream.output.arn
        }
        destination_schema {
          record_format_type = "JSON"
        }
      }
    }
  }

  tags = {
    Environment = "test"
  }
}

