provider "aws" {
  region = "us-east-1"
}

variable "domain_name" {
  default = "example.com"
}

variable "primary_fqdn" {
  default = "primary.example.com"
}

variable "secondary_fqdn" {
  default = "secondary.example.com"
}

# Hosted Zone named "main"
resource "aws_route53_zone" "main" {
  name = var.domain_name
}

# Primary Health Check using FQDN
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = var.primary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

# Secondary Health Check using FQDN
resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = var.secondary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

# Primary Failover Record
resource "aws_route53_record" "www_primary" {
  zone_id = aws_route53_zone.main.id
  name    = "www"
  type    = "A"
  # Replace with the actual IP address or use an alias configuration
  records = ["10.0.0.1"]
  ttl     = 60

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier  = "primary"
  health_check_id = aws_route53_health_check.primary_health_check.id
}

# Secondary Failover Record
resource "aws_route53_record" "www_secondary" {
  zone_id = aws_route53_zone.main.id
  name    = "www"
  type    = "A"
  # Replace with the actual IP address or use an alias configuration
  records = ["10.0.0.2"]
  ttl     = 60

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier  = "secondary"
  health_check_id = aws_route53_health_check.secondary_health_check.id
}

