provider "aws" {
  region = "us-east-1"
}

# Data source to locate the hosted zone named "primary"
# Note: In a real environment, zones are typically identified by domain names (e.g., example.com).
# This assumes a hosted zone with the name "primary" exists.
data "aws_route53_zone" "primary" {
  name = "primary"
}

# Traffic Policy Document
# Defines a Latency routing policy (interpreting "lowest load" as lowest latency/performance)
# directing traffic between us-east-1 and eu-central-1.
resource "aws_route53_traffic_policy" "lowest_load_policy" {
  name     = "lowest-load-policy"
  comment  = "Policy to direct traffic to the endpoint with lowest latency in us-east-1 or eu-central-1"
  document = <<EOF
{
  "AWSPolicyFormatVersion": "2015-10-01",
  "RecordType": "A",
  "StartRule": "latency-rule",
  "Endpoints": {
    "us-east-endpoint": {
      "Type": "value",
      "Value": "192.0.2.1"
    },
    "eu-central-endpoint": {
      "Type": "value",
      "Value": "192.0.2.2"
    }
  },
  "Rules": {
    "latency-rule": {
      "Type": "latency",
      "Endpoints": {
        "us-east-1": "us-east-endpoint",
        "eu-central-1": "eu-central-endpoint"
      }
    }
  }
}
EOF
}

# Traffic Policy Instance
# Applies the policy to a specific record within the "primary" hosted zone.
resource "aws_route53_traffic_policy_instance" "example" {
  hosted_zone_id = data.aws_route53_zone.primary.id
  name           = "load-balanced-primary"
  type           = "A"
  ttl            = 300

  traffic_policy_id   = aws_route53_traffic_policy.lowest_load_policy.id
  traffic_policy_version = aws_route53_traffic_policy.lowest_load_policy.version
}
