extracted_code:
provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
  default     = "my-eks-cluster"
}

variable "subnet_ids" {
  description = "A list of subnet IDs to associate with the Fargate profile. Ensure these subnets have the 'kubernetes.io/cluster/<cluster-name>: shared' tag."
  type        = list(string)
  default     = []
}

data "aws_eks_cluster" "cluster" {
  name = var.cluster_name
}

resource "aws_iam_role" "eks_fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eks_fargate_pod_execution_role_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.eks_fargate_pod_execution_role.name
}

resource "aws_eks_fargate_profile" "kube_system_profile" {
  name                   = "${var.cluster_name}-kube-system-profile"
  cluster_name           = var.cluster_name
  pod_execution_role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  # Ensure the selected subnets have the cluster-association resource tag:
  # Key: kubernetes.io/cluster/<cluster-name>
  # Value: shared or owned
}

resource "null_resource" "patch_coredns" {
  depends_on = [aws_eks_fargate_profile.kube_system_profile]

  provisioner "local-exec" {
    interpreter = ["/bin/bash", "-c"]

    command = <<EOF
      # Decode and save CA certificate to a temporary file
      echo "${data.aws_eks_cluster.this.certificate_authority[0].data}" | base64 -d > /tmp/ca.crt

      # Retrieve EKS authentication token
      TOKEN=$(aws eks get-token --cluster-name ${var.cluster_name} --query status.token --output text)

      # Patch the coredns deployment to allow scheduling on Fargate
      # This example removes the topology spread constraints which often block single-node Fargate scaling
      kubectl patch deployment coredns \n        -n kube-system \n        --server ${data.aws_eks_cluster.this.endpoint} \n        --certificate-authority /tmp/ca.crt \n        --token "$TOKEN" \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/spec/topologySpreadConstraints"}]'

      # Cleanup
      rm /tmp/ca.crt
    EOF
  }
}

