provider "aws" {
  region = "us-east-1"
}

variable "bucket_suffix" {
  description = "The suffix to append to the bucket names"
  type        = string
  default     = "test"
}

variable "local_file_path" {
  description = "The local path of the file to upload to the web data bucket"
  type        = string
  default     = "order_data2.csv"
}

# S3 Bucket for CloudGoat Data
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_data" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_data]

  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

# S3 Bucket for Website Data
resource "aws_s3_bucket" "web_data" {
  bucket = "web-data-${var.bucket_suffix}"
}

resource "aws_s3_object" "order_upload" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = var.local_file_path
}

resource "aws_s3_bucket_public_access_block" "web_data" {
  bucket = aws_s3_bucket.web_data.id

  ignore_public_acls      = true
  block_public_acls       = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_policy" "web_data" {
  bucket = aws_s3_bucket.web_data.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data.arn}/*"
      }
    ]
  })
}

