resource "aws_s3_bucket" "primary_bucket" {
  bucket_prefix = "primary-bucket-"
}

resource "aws_s3_bucket" "logging_bucket" {
  bucket_prefix = "logging-bucket-"
}

# Ownership controls are required to apply ACLs in modern AWS S3 configurations
resource "aws_s3_bucket_ownership_controls" "primary_ownership" {
  bucket = aws_s3_bucket.primary_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "logging_ownership" {
  bucket = aws_s3_bucket.logging_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Apply explicit ACLs
resource "aws_s3_bucket_acl" "primary_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.primary_ownership]
  bucket     = aws_s3_bucket.primary_bucket.id
  acl        = "private"
}

resource "aws_s3_bucket_acl" "logging_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.logging_ownership]
  bucket     = aws_s3_bucket.logging_bucket.id
  acl        = "log-delivery-write"
}

# Enable logging on the primary bucket to deliver to the logging bucket
resource "aws_s3_bucket_logging" "primary_logging" {
  bucket = aws_s3_bucket.primary_bucket.id

  # Connect the logging target bucket by its ID
  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "log/"

  # Ensure the ACL configuration is applied before logging is enabled
  depends_on = [aws_s3_bucket_acl.logging_acl]
}

