  vpc_id     = aws_vpc.redis_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_2" {
  vpc_id     = aws_vpc.redis_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Security Group to allow access to Redis
resource "aws_security_group" "redis_sg" {
  name        = "redis-security-group"
  description = "Allow inbound traffic for Redis"
  vpc_id      = aws_vpc.redis_vpc.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name       = "redis-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]
}

# Redis Replication Group (Single Node for this example)
resource "aws_elasticache_replication_group" "redis_replication_group" {
  replication_group_id          = "tf-redis-group"
  replication_group_description = "Terraform managed Redis instance"
  node_type                     = "cache.t3.micro"
  number_cache_clusters         = 1
  engine                        = "redis"
  engine_version                = "6.x"
  parameter_group_name          = "default.redis6.x"
  port                          = 6379
  subnet_group_name             = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids            = [aws_security_group.redis_sg.id]
  snapshot_retention_limit      = 5
  automatic_failover_enabled    = false
}

