terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and Subnet configuration required for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "redshift-subnet"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]

  tags = {
    Name = "Redshift Subnet Group"
  }
}

# Security Group to allow access (Adjust as needed for production)
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Cluster (Single Node)
resource "aws_redshift_cluster" "default" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "dev"
  master_username     = "admin"
  master_password     = "Terraform123!"
  node_type           = "dc2.large"
  number_of_nodes     = 1
  skip_final_snapshot = true

  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  publicly_accessible       = true

  tags = {
    Environment = "test"
  }
}

# Snapshot Schedule: Every 12 hours
# Cron syntax: cron(Minutes Hours Day-of-month Month Day-of-week Year)
# "cron(0 0/12 * * ? *)" runs at minute 0 of every 12th hour.
resource "aws_redshift_snapshot_schedule" "twelve_hour_schedule" {
  identifier  = "redshift-12h-schedule"
  description = "Automatic snapshots every 12 hours"

  schedule_definitions = [
    "cron(0 0/12 * * ? *)"
  ]

  tags = {
    Name = "12-hour-snapshot-schedule"
  }
}

# Associate the Snapshot Schedule with the Cluster
resource "aws_redshift_snapshot_schedule_association" "schedule_association" {
  cluster_identifier  = aws_redshift_cluster.default.cluster_identifier
  schedule_identifier = aws_redshift_snapshot_schedule.twelve_hour_schedule.id
}

