  cluster_identifier = "redshift-cluster-1"
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  database_name = "mydb"
  master_username = "foo"
  master_password = "Mustbe8characters"

  cluster_subnet_group_name   = aws_redshift_subnet_group.example_subnet_group.name

  skip_final_snapshot = true
}

