# Data source to retrieve default subnets
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "Redshift Subnet Group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift Security Group"
  }
}

# Redshift Cluster with Replication
resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "two-node-redshift-cluster"
  database_name       = "mydb"
  master_username     = "admin"
  master_password     = "TempPass123!"

  node_type       = "dc2.large"
  cluster_type    = "multi-node"
  number_of_nodes = 2

  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  publicly_accessible       = true

  # Snapshot Copy Configuration for Replication
  snapshot_copy {
    destination_region = "us-east-2"
    retention_period   = 7
    grant_name         = "cross-region-replication"
  }

  skip_final_snapshot = true

  tags = {
    Environment = "production"
  }
}
```

