provider "aws" {
  region = "us-east-1"
}

# 1. Generate a random password for the Redshift master user
resource "random_password" "master_password" {
  length  = 16
  special = true
}

# 2. Provision an IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the IAM role (e.g., S3 Read Access for loading data)
resource "aws_iam_role_policy_attachment" "redshift_s3_attach" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# 3. Create a Redshift Cluster
# Get default VPC
data "aws_vpc" "default" {
  default = true
}

# Create a Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  description = "Security group for Redshift cluster"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_redshift_cluster" "default" {
  cluster_identifier = "my-redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = random_password.master_password.result
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  skip_final_snapshot    = true
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

