provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lambda Execution
data "aws_iam_policy_document" "lambda_assume_role_policy" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "lambda_execution_role" {
  name               = "lambda_execution_role"
  assume_role_policy = data.aws_iam_policy_document.lambda_assume_role_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Data source for archiving the Lambda function code
# Note: Ensure a file named 'lambda_function.py' exists in the working directory 
# with the following content before running 'terraform apply':
#
# import json
# def lambda_handler(event, context):
#     return {
#         'statusCode': 200,
#         'body': json.dumps('Hello from Terraform!')
#     }
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda_function.py"
  output_path = "lambda_function_payload.zip"
}

# Lambda Function Resource
resource "aws_lambda_function" "example_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "example_lambda"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "lambda_function.lambda_handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "python3.9"
}

# Lambda Invocation Resource
resource "aws_lambda_invocation" "example_lambda_invocation" {
  function_name = aws_lambda_function.example_lambda.function_name
  input         = jsonencode({
    key1 = "value1"
    key2 = "value2"
  })

  depends_on = [
    aws_lambda_function.example_lambda
  ]
}

