variable "table_name" {
  description = "The name of the DynamoDB table to analyze"
  type        = string
  default     = "contributor-insights-table"
}

variable "index_name" {
  description = "(Optional) The name of a Global Secondary Index to analyze"
  type        = string
  default     = null
}

# Example DynamoDB Table Setup
resource "aws_dynamodb_table" "example" {
  name           = var.table_name
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  # Defining a GSI to demonstrate index-level insights configuration
  global_secondary_index {
    name            = "TestGSI"
    hash_key        = "id"
    projection_type = "ALL"
  }
}

# Contributor Insights for the DynamoDB Table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.example.name
}

# Contributor Insights for a specific Global Secondary Index
# This resource is only created if an index_name is provided
resource "aws_dynamodb_contributor_insights" "index_insights" {
  count      = var.index_name != null ? 1 : 0
  table_name = aws_dynamodb_table.example.name
  index_name = var.index_name != null ? var.index_name : "TestGSI"
}

