provider "aws" {
  region = "us-east-1"
}

# VPC for DAX
resource "aws_vpc" "dax_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "dax-vpc"
  }
}

# Subnet for DAX
resource "aws_subnet" "dax_subnet" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet"
  }
}

# Security Group for DAX
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow traffic for DAX cluster"
  vpc_id      = aws_vpc.dax_vpc.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-security-group"
  }
}

# IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Attach Policy to IAM Role
resource "aws_iam_role_policy_attachment" "dax_policy_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDAXServicePolicyForDynamoDBAccess"
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name = "dax-subnet-group"
  subnet_ids = [
    aws_subnet.dax_subnet.id
  ]
}

# DAX Cluster
resource "aws_dax_cluster" "example_cluster" {
  cluster_name       = "example-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_factor = 1
  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_sg.id]

  tags = {
    Environment = "example"
  }
}

