  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "sagemaker-subnet-a"
  }
}

resource "aws_subnet" "sagemaker_subnet_b" {
  vpc_id     = aws_vpc.sagemaker_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "sagemaker-subnet-b"
  }
}

resource "aws_security_group" "sagemaker_sg" {
  name        = "sagemaker-domain-sg"
  description = "Security group for SageMaker Domain"
  vpc_id      = aws_vpc.sagemaker_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "sagemaker-domain-sg"
  }
}

resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

resource "aws_sagemaker_domain" "this" {
  domain_name = "example-sagemaker-domain"
  auth_mode   = "IAM"

  vpc_config {
    subnet_ids = [
      aws_subnet.sagemaker_subnet_a.id,
      aws_subnet.sagemaker_subnet_b.id
    ]
    security_group_ids = [aws_security_group.sagemaker_sg.id]
  }

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    security_groups = [aws_security_group.sagemaker_sg.id]

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
        lifecycle_config_arns = []
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
        lifecycle_config_arns = []
      }
    }

    sharing_settings {
      notebook_output_option = "Allowed"
    }
  }

  tags = {
    Purpose = "TerraformAI-Demo"
  }
}
```

