# IAM Role for SageMaker Pipeline
resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_execution_policy" {
  role       = aws_iam_role.sagemaker_pipeline_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Pipeline Resource
resource "aws_sagemaker_pipeline" "example_pipeline" {
  name        = "example-inference-pipeline"
  role_arn    = aws_iam_role.sagemaker_pipeline_role.arn
  display_name = "Example ML Pipeline"

  # Pipeline definition provided inline using jsonencode
  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Metadata = {
      ProjectId = "example-project"
    }
    Parameters = [
      {
        Name = "InputDataUrl"
        DefaultValue = "s3://my-bucket/input-data/"
        Type = "String"
      },
      {
        Name = "InstanceType"
        DefaultValue = "ml.m5.xlarge"
        Type = "String"
      }
    ]
    PipelineExperimentConfig = {
      ExperimentName = "ExampleExperiment"
      TrialName      = "ExampleTrial"
    }
    Steps = [
      {
        Name = "ProcessingStep"
        Type = "Processing"
        Description = "Preprocess data"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount     = 1
              InstanceType      = "ml.m5.xlarge"
              VolumeSizeInGB    = 30
              VolumeKmsKeyId    = null
            }
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1"
            ContainerEntrypoint = ["python3", "/opt/ml/processing/input/code/preprocess.py"]
          }
          ProcessingInputs = [
            {
              InputName = "input_data"
              S3Input = {
                S3Uri = "{{ProcessingParameters.InputDataUrl}}"
                LocalPath = "/opt/ml/processing/input"
                S3DataType = "S3Prefix"
                S3DataDistributionType = "FullyReplicated"
              }
            },
            {
              InputName = "code"
              S3Input = {
                S3Uri = "s3://my-bucket/code/preprocess.py"
                LocalPath = "/opt/ml/processing/input/code"
                S3DataType = "S3Prefix"
                S3DataDistributionType = "FullyReplicated"
              }
            }
          ]
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "train_data"
                S3Output = {
                  S3Uri = "s3://my-bucket/preprocessed-data/train/"
                  LocalPath = "/opt/ml/processing/output/train"
                  S3UploadMode = "EndOfJob"
                }
              },
              {
                OutputName = "test_data"
                S3Output = {
                  S3Uri = "s3://my-bucket/preprocessed-data/test/"
                  LocalPath = "/opt/ml/processing/output/test"
                  S3UploadMode = "EndOfJob"
                }
              }
            ]
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
        }
      },
      {
        Name = "TrainingStep"
        Type = "Training"
        DependsOn = ["ProcessingStep"]
        Description = "Train the model"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.5-1"
            TrainingInputMode = "File"
          }
          OutputDataConfig = {
            S3OutputPath = "s3://my-bucket/model-output/"
          }
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri = "{{Steps.ProcessingStep.ProcessingOutputConfig.Outputs[0].S3Output.S3Uri}}"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
            },
            {
              ChannelName = "validation"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri = "{{Steps.ProcessingStep.ProcessingOutputConfig.Outputs[1].S3Output.S3Uri}}"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
            }
          ]
          ResourceConfig = {
            InstanceCount = 1
            InstanceType = "{{ProcessingParameters.InstanceType}}"
            VolumeSizeInGB = 30
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 86400
            MaxWaitTimeInSeconds = 86400
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
        }
      }
    ]
  })

  tags = {
    Environment = "dev"
    ManagedBy   = "Terraform"
  }
}

