  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "fleet-sg"
  }
}

# Data Source: Latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Launch Template
resource "aws_launch_template" "fleet_template" {
  name_prefix   = "fleet-template-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "demo-key" # Replace with your actual key pair name

  network_interfaces {
    associate_public_ip_address = false
    subnet_id                   = aws_subnet.private.id
    security_groups             = [aws_security_group.fleet_sg.id]
  }

  tag_specifications {
    resource_type = "instance"

    tags = {
      Name = "Fleet-Instance"
    }
  }
}

# EC2 Fleet
resource "aws_ec2_fleet" "example_fleet" {
  terminate_instances_with_expiration = false
  type                                = "maintain"

  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.fleet_template.id
      version            = "$Latest"
    }

    override {
      instance_type = "t3.micro"
    }
  }

  target_capacity_specification {
    total_target_capacity       = 9
    on_demand_target_capacity   = 5
    spot_target_capacity        = 4
    default_target_capacity_type = "on-demand"
  }

  on_demand_options {
    single_instance_type = true
  }

  spot_options {
    single_instance_type = true
  }

  depends_on = [aws_launch_template.fleet_template, aws_nat_gateway.nat]
}
