  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-db-subnet"
  }
}

# NAT Gateway for Private Subnets (to allow updates/outbound access)
