    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Database SG (Talks to App Server)
resource "aws_security_group" "db_sg" {
  name        = "db-sg"
  description = "Allow MySQL traffic from App Server"
  vpc_id      = aws_vpc.main.id

