# Strategy: Implement an In-Memory Caching Layer (AWS ElastiCache for Redis)
# By caching frequently accessed data, the application reduces direct read load on the primary database.

provider "aws" {
  region = "us-east-1"
}

# VPC for isolated resources
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "cache-vpc"
  }
}

# Subnets for High Availability
resource "aws_subnet" "cache_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "cache-subnet-1"
  }
}

resource "aws_subnet" "cache_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "cache-subnet-2"
  }
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "default" {
  name        = "tf-redis-subnet-group"
  description = "Terraform Redis subnet group"
  subnet_ids  = [aws_subnet.cache_subnet_1.id, aws_subnet.cache_subnet_2.id]
}

# Security Group to allow access to Redis
resource "aws_security_group" "redis_sg" {
  name        = "redis-sg"
  description = "Allow Redis inbound traffic"
  vpc_id      = aws_vpc.main.id
}

# Allow inbound traffic on Redis port (6379) from within the VPC
resource "aws_vpc_security_group_ingress_rule" "allow_redis" {
  security_group_id = aws_security_group.redis_sg.id
  cidr_ipv4         = aws_vpc.main.cidr_block
  from_port         = 6379
  ip_protocol       = "tcp"
  to_port           = 6379
}

# ElastiCache Replication Group (Redis Cluster)
resource "aws_elasticache_replication_group" "redis" {
  replication_group_id          = "tf-replication-group"
  replication_group_description = "Terraform Redis Replication Group for caching"
  node_type                     = "cache.t3.micro"
  number_cache_clusters         = 2
  engine                        = "redis"
  engine_version                = "7.0"
  parameter_group_name          = "default.redis7"
  subnet_group_name             = aws_elasticache_subnet_group.default.name
  security_group_ids            = [aws_security_group.redis_sg.id]
  automatic_failover_enabled    = true
  multi_az_enabled              = true

  snapshot_retention_limit = 5
  snapshot_window          = "03:00-05:00"
}

output "redis_primary_endpoint" {
  description = "Primary endpoint for Redis connection"
  value       = aws_elasticache_replication_group.redis.primary_endpoint_address
}

