# Define the authentication password (ideally pass this via a variable or secret manager)
variable "redis_password" {
  type        = string
  description = "The password for the Redis user"
  sensitive   = true
  default     = "ChangeMe123!"
}

resource "aws_elasticache_user" "redis_user" {
  engine        = "redis"
  user_name     = "my_redis_user"
  access_string = "on ~* +@all" # Grants access to all keys and commands

  authentication_mode {
    type      = "password"
    passwords = [var.redis_password]
  }
}

resource "aws_elasticache_user_group" "redis_user_group" {
  engine        = "redis"
  user_group_id = "my_user_group"
