  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_key.key_id
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "encrypted-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Configuration for encryption at rest
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  tags = {
    Name = "encrypted-msk-cluster"
  }
}
