terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source to get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Subnets for the MSK Cluster (MSK Serverless requires subnets in at least one AZ)
resource "aws_subnet" "msk_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index + 1}"
  }
}

# Security Group for the MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for Amazon MSK Serverless cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rule for Kafka clients (adjust port/cidr as needed)
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# Amazon MSK Serverless Cluster
resource "aws_msk_cluster" "serverless" {
  cluster_name = "terraform-msk-serverless-cluster"
  kafka_version = "2.8.1" # MSK Serverless specific version

  # Configuration for Serverless
  serverless {
    vpc_config {
      subnet_ids         = aws_subnet.msk_subnet[*].id
      security_group_ids = [aws_security_group.msk_sg.id]
    }
  }

  # Client Authentication
  client_authentication {
    sasl {
      scram = true # SASL/SCRAM is supported for Serverless
    }
  }

  # Encryption Configuration
  encryption_info {
    encryption_at_rest_kms_key_arn = null # Uses AWS Managed Key by default
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  tags = {
    Name = "terraform-msk-serverless"
  }
}

