provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Create three subnets in three different Availability Zones
# MSK Serverless requires subnets in at least 3 AZs
resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index}"
  }
}

# Data source for Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka plaintext traffic (typically 9092/9094/9096 depending on config)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# MSK Serverless Cluster
resource "aws_msk_serverless_cluster" "example" {
  cluster_name           = "msk-serverless-cluster"
  vpc_config {
    subnet_ids         = aws_subnet.msk_subnets[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  tags = {
    Name = "msk-serverless-cluster"
  }
}

