terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# --- VPC and Networking ---
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

resource "aws_security_group" "msk_security_group" {
  name_prefix = "msk-sg-"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow Kafka broker traffic
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- S3 for Custom Plugin ---
# In a real scenario, you would upload your actual debezium.zip file.
# Here we create a bucket and a mock object for the Terraform to reference.
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugins-bucket-unique-id"
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "/dev/null" # Placeholder
  etag   = filemd5("/dev/null")
}

# --- IAM Role for MSK Connect ---
data "aws_iam_policy_document" "msk_connect_assume_role" {
  statement {
    effect = "allow"

    principals {
      type        = "Service"
      identifiers = ["kafkaconnect.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "msk_connect_role" {
  name               = "msk-connect-role"
  assume_role_policy = data.aws_iam_policy_document.msk_connect_assume_role.json
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSMSKConnectServiceRolePolicy"
}

# --- MSK Cluster ---
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_security_group.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.example.arn
    encryption_in_transit {
      client_broker = "PLAINTEXT"
      in_cluster    = true
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }

  tags = {
    Name = "example-msk-cluster"
  }
}

resource "aws_msk_configuration" "example" {
  kafka_versions = ["2.8.1"]
  name           = "example-msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.network.threads=3
num.partitions=1
num.recovery.threads.per.data.dir=1
num.io.threads=8
socket.send.buffer.bytes=102400
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
num.partitions=1
num.recovery.threads.per.data.dir=1
log.retention.hours=168
log.segment.bytes=1073741824
log.retention.check.interval.ms=300000
zookeeper.connect.timeout.ms=6000
PROPERTIES
}

resource "aws_kms_key" "example" {
  description = "MSK Cluster Key"
}

# --- MSK Connect Custom Plugin ---
resource "aws_mskconnect_custom_plugin" "debezium" {
  name           = "debezium-plugin"
  content_type   = "ZIP"
  location {
    s3_bucket_name = aws_s3_bucket.plugin_bucket.id
    s3_object_key  = aws_s3_object.debezium_plugin.key
  }
}

# --- MSK Connect Connector ---
resource "aws_mskconnect_connector" "example" {
  name = "debezium-connector"
  capacity {
    provisioned {
      mcu_count    = 1
      worker_count = 1
    }
  }

  connector_configuration = {
    "connector.class"              = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname"            = "your-db-hostname"
    "database.port"                = "3306"
    "database.user"                = "user"
    "database.password"            = "password"
    "database.server.id"           = "184054"
    "database.server.name"         = "my-app-connector"
    "database.include.list"        = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_iam[0] # Using SASL IAM
    "database.history.kafka.topic" = "schema-changes.inventory"
    "include.schema.changes"       = "true"
  }

  kafkacluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam[0]
      vpc {
        subnet_ids = [aws_subnet.msk_subnet[0].id]
        security_groups = [aws_security_group.msk_security_group.id]
      }
    }
  }

  kafkaconnect_version = "2.7.1"

  plugin_location {
    plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  depends_on = [
    aws_msk_cluster.example,
    aws_mskconnect_custom_plugin.debezium
  ]
}
