provider "aws" {
  region = "us-east-1"
}

# --- Data Sources ---
data "aws_availability_zones" "available" {}

# --- VPC and Networking ---
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "msk-vpc" }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = { Name = "msk-subnet-${count.index}" }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK cluster and Connect"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  ingress {
    from_port   = 9096
    to_port     = 9096
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- KMS Key for Encryption ---
resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_key.key_id
}

# --- Logging Infrastructure ---

# CloudWatch Logs Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7
}

# S3 Bucket for Logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-bucket-unique-id"
}

resource "aws_s3_bucket_versioning" "msk_logs_versioning" {
  bucket = aws_s3_bucket.msk_logs_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Kinesis Data Firehose
resource "aws_iam_role" "firehose_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "firehose.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFirehoseFullAccess"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-logs-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
    prefix     = "logs/"
  }
}

# --- IAM Role for MSK Cluster ---
resource "aws_iam_role" "msk_cluster_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "kafka.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_cluster_logging_policy" {
  name = "msk-logging-policy"
  role = aws_iam_role.msk_cluster_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord"
        ]
        Resource = "${aws_kinesis_firehose_delivery_stream.msk_firehose.arn}"
      }
    ]
  })
}

# --- Amazon MSK Cluster ---
resource "aws_msk_cluster" "main" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    cloudwatch_logs {
      log_group = aws_cloudwatch_log_group.msk_log_group.name
      enabled   = true
    }

    firehose {
      delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      enabled         = true
    }

    s3 {
      bucket   = aws_s3_bucket.msk_logs_bucket.bucket
      prefix   = "logs/msk-broker/"
      enabled  = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_brokers = true
      }
      node_exporter {
        enabled_in_brokers = true
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  tags = {
    Name = "terraform-msk"
  }
}

resource "aws_msk_configuration" "example" {
  kafka_versions = ["3.5.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
num.partitions=3
PROPERTIES
}

# --- MSK Connect ---

# S3 Bucket for Artifacts (Plugin)
resource "aws_s3_bucket" "artifacts_bucket" {
  bucket = "msk-connect-artifacts-bucket-unique-id"
}

# Assuming debezium.zip exists locally, we upload it to the artifacts bucket
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.artifacts_bucket.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip" # This file must exist locally
  etag   = filemd5("debezium.zip")
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name        = "debezium-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.artifacts_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
      object_version = "latest"
    }
  }
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "kafkaconnect.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_basic" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKConnectServiceRole"
}

# Example secret for Debezium
resource "aws_secretsmanager_secret" "db_secret" {
  name = "msk-connect/db-secret"
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = "password"
  })
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "main" {
  name = "debezium-connector"

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = split(",", aws_msk_cluster.main.bootstrap_brokers_sasl_iam["public"]) # Adjust based on network access
      vpc_subnet_ids   = aws_subnet.msk_subnet[*].id
    }
    authentication_method = "SASL_IAM"
  }

  kafka_client {
    msk_connect_custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium.arn
      revision = aws_mskconnect_custom_plugin.debezium.latest_revision
    }

    capabilities = ["SOURCE"]

    user_properties = {
      "database.hostname" = "your-db-host"
      "database.port"     = "5432"
      "database.user"     = "admin"
      "database.password" = aws_secretsmanager_secret.db_secret.arn
      "database.server.name" = "my-db-server"
      "connector.class"    = "io.debezium.connector.postgresql.PostgresConnector"
    }

    msconnect_worker_configuration = {
      # Optional: specify worker config if needed, otherwise defaults apply
    }
  }

  capacity {
    provisioned_capacity {
      mcu_count    = 2
      worker_count = 1
    }
  }

  connector_configuration = {
    "database.hostname" = "your-db-host"
    "database.port"     = "5432"
    "database.user"     = "admin"
    "database.password" = "${aws_secretsmanager_secret.db_secret.arn}:password" # Reference to secret ARN + key
    "database.server.name" = "my-db-server"
    "plugin.name"        = "debezium"
    "tasks.max"          = "1"
  }

  aws_service_role_arn = aws_iam_role.msk_connect_role.arn
}
