provider "aws" {
  region = "us-east-1"
}

# Random password for the database
resource "random_password" "password" {
  length  = 16
  special = true
}

# VPC and Networking setup
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "private" {
  count             = 3
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
}

resource "aws_db_subnet_group" "main" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

resource "aws_security_group" "mysql" {
  name_prefix = "mysql-cluster-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Aurora MySQL Cluster
# Note: Aurora manages storage automatically across the zones. 
# The "100 GB" request is represented by the cluster configuration, 
# though Aurora storage is elastic and scales automatically.
resource "aws_rds_cluster" "main" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                 = "aurora-mysql"
  engine_version         = "8.0.mysql_aurora.3.02.0"
  database_name          = "mydb"
  master_username        = "admin"
  master_password        = random_password.password.result
  db_cluster_instance_class = "db.t3.small"
  vpc_security_group_ids = [aws_security_group.mysql.id]
  db_subnet_group_name  = aws_db_subnet_group.main.name
  storage_encrypted      = true
  skip_final_snapshot    = true

  # Ensure high availability across zones
  # storage is replicated across 3 AZs automatically in Aurora
}

# Writer Instance
resource "aws_rds_cluster_instance" "writer" {
  identifier         = "aurora-mysql-writer"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version
}

# Reader Instance (to demonstrate multi-zone clustering)
resource "aws_rds_cluster_instance" "reader" {
  count              = 1
  identifier         = "aurora-mysql-reader-${count.index}"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version
}

