terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@" 
}

# Retrieve the default VPC
data "aws_vpc" "default" {
  default = true
}

# Retrieve default subnets in the VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "mysql-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My MySQL Subnet Group"
  }
}

# Create a Security Group for MySQL
resource "aws_security_group" "mysql_sg" {
  name        = "mysql-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Note: Restrict this IP range in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-sg"
  }
}

# Create the MySQL Database Instance
resource "aws_db_instance" "mysql" {
  identifier             = "my-mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = false
  db_name                = "mydb"
  username               = "admin"
  password               = random_password.db_password.result
  parameter_group_name   = "default.mysql8.0"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.mysql_sg.id]
  publicly_accessible    = true # Note: Set to false for production
  skip_final_snapshot    = true
  multi_az               = false

  tags = {
    Name = "MySQL-Instance"
  }
}

# Output the database endpoint and password
output "db_endpoint" {
  description = "The connection endpoint for the database"
  value       = aws_db_instance.mysql.endpoint
}

output "db_password" {
  description = "The database password"
  sensitive   = true
  value       = random_password.db_password.result
}

