provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# Subnets
resource "aws_subnet" "dax_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.dax_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.dax_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "dax-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

# Internet Gateway (for network access)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.dax_vpc.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.dax_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.dax_subnet[count.index].id
  route_table_id = aws_route_table.public.id
}

# IAM Role for DAX to access DynamoDB
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dax_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Security Group
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow inbound DAX traffic"
  vpc_id      = aws_vpc.dax_vpc.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-sg"
  }
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "main" {
  name = "dax-subnet-group"
  description = "DAX subnet group"

  subnet_ids = aws_subnet.dax_subnet[*].id
}

# DAX Cluster
resource "aws_dax_cluster" "main" {
  cluster_name              = "terraform-dax-cluster"
  iam_role_arn              = aws_iam_role.dax_role.arn
  node_type                 = "dax.t3.small"
  replication_factor        = 1
  subnet_group_name         = aws_dax_subnet_group.main.name
  security_group_ids        = [aws_security_group.dax_sg.id]
  cluster_endpoint_encryption_type = "NONE"

  tags = {
    Environment = "production"
  }
}

