provider "aws" {
  region = "us-east-1"
}

# 1. Networking Setup (VPC and two Sample Subnets)
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 2. Neptune Subnet Group
resource "aws_neptune_subnet_group" "main" {
  name        = "neptune-subnet-group"
  description = "Neptune subnet group for sample cluster"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# 3. Security Group (Restricts access to the two sample subnets)
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic only from sample subnets"
  vpc_id      = aws_vpc.neptune_vpc.id

  # Ingress rule: Port 8182 restricted to the CIDR blocks of the two subnets
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block, aws_subnet.subnet_2.cidr_block]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 4. Custom Parameter Group
resource "aws_neptune_parameter_group" "custom" {
  name        = "neptune-custom-parameter-group"
  description = "Custom Neptune parameter group"
  family      = "neptune1"

  # Example parameter modification
  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 5. Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "neptune-cluster-demo"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  neptune_subnet_group_name       = aws_neptune_subnet_group.main.name
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]
  db_cluster_parameter_group_name = aws_neptune_parameter_group.custom.name

  tags = {
    Name = "neptune-cluster-demo"
  }
}

# 6. Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  identifier         = "neptune-instance-demo"
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t4g.medium"
  apply_immediately  = true

  tags = {
    Name = "neptune-instance-demo"
  }
}

