extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# SNS Topic for streaming notifications
resource "aws_sns_topic" "chime_streaming_notifications" {
  name = "chime-streaming-notifications"
}

# Encrypted AWS Chime Voice Connector
resource "aws_chime_voice_connector" "encrypted_connector" {
  name               = "encrypted-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# Streaming Configuration
# Sets retention, enables SNS notifications, and omits Kinesis configuration (disabled/streaming off)
resource "aws_chime_voice_connector_streaming" "streaming_config" {
  voice_connector_id = aws_chime_voice_connector.encrypted_connector.id

  # Retain records for 5 hours
  data_retention = 5

  # "Amazon Kinesis streaming is turned off" - implying the streaming service itself is disabled
  # or specifically that no Kinesis Video/Data Stream destination is configured while retaining
  # the metadata configuration (SNS) and retention policy as requested.
  disabled = true

  streaming_configuration {
    streaming_notification_targets {
      sns_topic_arn = aws_sns_topic.chime_streaming_notifications.arn
    }
  }
}

