extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Resource: Kinesis Video Stream
# Chime Voice Connector media streams are sent to Kinesis Video Streams (KVS).
resource "aws_kinesis_video_stream" "chime_media" {
  name                    = "chime-voice-connector-media"
  data_retention_in_hours = 24
  device_name             = "chime-vc"
  media_type              = "video/h264" # KVS requires a media type; Chime streams audio tracks within this container
  tags = {
    Environment = "Production"
  }
}

# Resource: AWS Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "example-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"

  tags = {
    Environment = "Production"
  }
}

# Resource: Voice Connector Streaming Configuration
# This enables the streaming of media to Kinesis Video Streams.
resource "aws_chime_voice_connector_streaming_configuration" "main" {
  voice_connector_id = aws_chime_voice_connector.main.id

  streaming_configuration {
    data_retention_in_hours = 2
    disabled                = false
    stream_type             = "MEDIATYPE_AUDIO"
  }
}

