    Name = "My Redshift Subnet Group"
  }
}

# SNS Topic for Event Notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-event-notifications"
}

# IAM Role for Redshift to send notifications (Optional if using SNS subscriptions securely, 
# but usually Redshift just needs permission to publish to SNS if configured, 
# though event subscriptions generally don't require a complex role attached to the cluster itself, 
# rather the subscription service handles the delivery).
# Standard Redshift event subscription is resource-based.

# Redshift Cluster
resource "aws_redshift_cluster" "default" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "mydb"
  master_username     = "admin"
  master_password     = random_password.redshift_password.result
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.default.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  skip_final_snapshot  = true
  publicly_accessible  = true

  tags = {
    Environment = "terraform-demo"
  }
}

# Redshift Event Subscription
resource "aws_redshift_event_subscription" "default" {
  name        = "redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  # Subscribe to events for the specific cluster
  source_ids   = [aws_redshift_cluster.default.cluster_identifier]
  source_type  = "cluster"

  # Event categories to notify on
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  tags = {
    Name = "redshift-event-subscription"
  }
}

