  region = "us-east-1"
}

# Generate a secure random password for the Redshift cluster
resource "random_password" "redshift_master_password" {
  length           = 16
  special          = true
  override_special = "_%@"
}

# Create VPC for the Redshift Cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create Subnets (Redshift requires a Subnet Group with at least 2 subnets in different AZs for Multi-AZ, or 1 for Single-AZ)
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Create Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Create Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "redshift-subnet-group"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Create SNS Topic for Event Notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-event-notifications"
}

# Create Redshift Cluster
resource "aws_redshift_cluster" "default" {
  cluster_identifier     = "tf-redshift-cluster"
  database_name          = "mydb"
  master_username        = "admin"
  master_password        = random_password.redshift_master_password.result
  node_type              = "dc2.large"
  cluster_type           = "single-node"
  number_of_nodes        = 1
  skip_final_snapshot    = true
  publicly_accessible    = true

  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]

  tags = {
    Environment = "production"
  }
}

# Create Redshift Event Subscription
resource "aws_redshift_event_subscription" "default" {
  name        = "redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  # Subscribe to configuration and availability events
  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.default.cluster_identifier]

  event_categories = [
    "configuration",
    "availability",
    "monitoring"
  ]

  depends_on = [aws_redshift_cluster.default]
}

