```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for the bucket name to avoid conflicts
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# Create the S3 Bucket
resource "aws_s3_bucket" "image_store" {
  bucket = "website-images-${random_string.suffix.result}"
}

# Configure Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "image_store" {
  bucket = aws_s3_bucket.image_store.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Set ownership controls to BucketOwnerPreferred
resource "aws_s3_bucket_ownership_controls" "image_store" {
  bucket = aws_s3_bucket.image_store.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Configure Public Access Block
# We must allow public policies to make objects readable via a bucket policy
resource "aws_s3_bucket_public_access_block" "image_store" {
  bucket = aws_s3_bucket.image_store.id

  block_public_acls       = true
  block_public_policy     = false
  ignore_public_acls      = true
  restrict_public_buckets = false
}

# Bucket Policy to allow public read access to all objects in the bucket
resource "aws_s3_bucket_policy" "allow_public_read" {
  bucket = aws_s3_bucket.image_store.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.image_store.arn}/*"
      },
    ]
  })
}

# Output the Bucket Name and URL
output "bucket_name" {
  value = aws_s3_bucket.image_store.id
}

output "bucket_endpoint" {
  value = aws_s3_bucket.image_store.website_endpoint
}
```

