  bucket = random_pet.bucket_name.id
}

# Configure bucket ownership to support ACLs
resource "aws_s3_bucket_ownership_controls" "pdf_host" {
  bucket = aws_s3_bucket.pdf_host.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Allow public access (required for hosting)
resource "aws_s3_bucket_public_access_block" "pdf_host" {
  bucket = aws_s3_bucket.pdf_host.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Set the bucket ACL to public-read
resource "aws_s3_bucket_acl" "pdf_host" {
  depends_on = [
    aws_s3_bucket_ownership_controls.pdf_host,
    aws_s3_bucket_public_access_block.pdf_host,
  ]

  bucket = aws_s3_bucket.pdf_host.id
  acl    = "public-read"
}

# Upload the PDF file
