  bucket       = aws_s3_bucket.pdf_host.id
  key          = "test.pdf"
  source       = "assets/test.pdf"
  acl          = "public-read"
  content_type = "application/pdf"

  # Ensure the file exists locally before trying to upload
  depends_on = [
    aws_s3_bucket_acl.pdf_host
  ]
}

