provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "example" {
  bucket = "my-static-website-example-bucket"
}

# Configure S3 Bucket for Static Website Hosting
resource "aws_s3_bucket_website_configuration" "example" {
  bucket = aws_s3_bucket.example.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Ownership controls required to use ACLs
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Public Access Block configuration to allow public read access for the website
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# ACL to make the bucket content publicly readable
resource "aws_s3_bucket_acl" "example" {
  depends_on = [
    aws_s3_bucket_ownership_controls.example,
    aws_s3_bucket_public_access_block.example,
  ]

  bucket = aws_s3_bucket.example.id
  acl    = "public-read"
}

# Upload a sample index.html file
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.example.id
  key          = "index.html"
  content      = "<html><body><h1>It Works!</h1></body></html>"
  content_type = "text/html"
  acl          = "public-read"
}

# Upload a sample error.html file
resource "aws_s3_object" "error" {
  bucket       = aws_s3_bucket.example.id
  key          = "error.html"
  content      = "<html><body><h1>404 - Error</h1></body></html>"
  content_type = "text/html"
  acl          = "public-read"
}

# Output the website endpoint
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.example.website_endpoint
}

