}

# Destination bucket for logs
resource "aws_s3_bucket" "log_destination" {
  bucket = "my-logging-destination-bucket"
}

# ACL required to allow the source bucket to write logs to this bucket
resource "aws_s3_bucket_acl" "log_destination_acl" {
  bucket = aws_s3_bucket.log_destination.id
  acl    = "log-delivery-write"
