provider "aws" {
  region = var.aws_region
}

# Variables for configuration
variable "aws_region" {
  description = "AWS Region where resources will be created"
  default     = "us-east-1"
}

variable "project_name" {
  description = "Name of the autograding project"
  default     = "cs-course-autograder"
}

variable "github_repo_url" {
  description = "HTTPS URL of the student's or template GitHub repository"
  type        = string
}

variable "github_access_token" {
  description = "GitHub Personal Access Token to access private repositories"
  type        = string
  sensitive   = true
}

variable "environment_image" {
  description = "Docker image for the build environment (e.g., Python, Java, Node)"
  default     = "aws/codebuild/standard:5.0"
}

# Data source to get current account details
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# ---------------------------------------------------------
# S3 Bucket for Artifacts and Logs
# ---------------------------------------------------------
resource "aws_s3_bucket" "grading_artifacts" {
  bucket = "${var.project_name}-artifacts-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# ---------------------------------------------------------
# IAM Role for CodeBuild
# ---------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy Attachment for CodeBuild Base Permissions
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# Custom IAM Policy for S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.project_name}*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.grading_artifacts.arn,
          "${aws_s3_bucket.grading_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases"
        ]
        Resource = "arn:aws:codebuild:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:report-group/${var.project_name}*"
      }
    ]
  })
}

# ---------------------------------------------------------
# CodeBuild Source Credentials (GitHub)
# ---------------------------------------------------------
resource "aws_codebuild_source_credential" "github_creds" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_access_token
}

# ---------------------------------------------------------
# CodeBuild Report Group (For Grading Results)
# ---------------------------------------------------------
resource "aws_codebuild_report_group" "grading_reports" {
  name = "${var.project_name}-test-reports"
  type = "TEST"

  export_config {
    type = "S3"

    s3_destination {
      bucket              = aws_s3_bucket.grading_artifacts.id
      packaging           = "ZIP"
      encryption_disabled = false
    }
  }
}

# ---------------------------------------------------------
# CodeBuild Project
# ---------------------------------------------------------
resource "aws_codebuild_project" "autograder" {
  name         = var.project_name
  description  = "Autograding system for CS course student repositories"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  source {
    type                = "GITHUB"
    location            = var.github_repo_url
    git_clone_depth     = 1
    report_build_status = true

    # Use OAuth for private repo access
    auth {
      type     = "OAUTH"
      resource = aws_codebuild_source_credential.github_creds.arn
    }
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = var.environment_image
    type         = "LINUX_CONTAINER"

    # Pass environment variables needed for grading
    environment_variable {
      name  = "PYTHON_VERSION"
      value = "3.9"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.project_name}"
      stream_name = "student-builds"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_artifacts.id}/build-logs"
    }
  }

  # Inline BuildSpec to define the grading workflow
  buildspec = templatefile("${path.module}/buildspec.tpl", {
    report_group_name = aws_codebuild_report_group.grading_reports.name
  })

  # Optional: Enable concurrent builds if multiple students submit at once
  concurrent_build_limit = 5
}

