}

# S3 Bucket to store grading results and reports
resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-course-autograder-results"
}

resource "aws_s3_bucket_versioning" "autograder_results_versioning" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM Role for CodeBuild to access S3 and CloudWatch
resource "aws_iam_role" "codebuild_role" {
  name = "autograder_codebuild_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Policy granting CodeBuild permissions to log and store artifacts
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Build Logs
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 7
}

# CodeBuild Project for Autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-course-autograder"
  description   = "Build project to execute and grade student code submissions"
  build_timeout = "15"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    # Uploads the grading report JSON generated by the buildspec to S3
    location = aws_s3_bucket.autograder_results.bucket
    name     = "grading-results.zip"
    packaging = "ZIP"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:6.0"
    type         = "LINUX_CONTAINER"

    environment_variable {
      name  = "REPORT_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "autograder-stream"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-template.git"
    git_clone_depth = 1

    # In a real scenario, use aws_codebuild_source_credential for OAUTH
    auth {
      type = "OAUTH"
    }
  }

  source_version = "main"
}

# Optional: Sample buildspec.yml to be placed in the root of the student repo
# This file instructs CodeBuild on how to run the tests and generate the report.
/*
# buildspec.yml
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
    commands:
      - echo "Installing dependencies..."
      - pip install pytest
  build:
    commands:
      - echo "Running grading script..."
      - pytest test_assignment.py --junitxml=report.xml || true
      - python generate_grading_json.py report.xml > grading_result.json
  post_build:
    commands:
      - echo "Build completed. Uploading artifacts."
artifacts:
  files:
    - 'grading_result.json'
    - 'report.xml'
*/

