provider "aws" {
  region = var.aws_region
}

# Generate a unique suffix for resource naming to avoid conflicts
resource "random_pet" "this" {
  length = 2
}

# -----------------------------------------------------------------------------
# S3 Bucket for Grading Outputs and Artifacts
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "grading_output" {
  bucket_prefix = "autograding-results-${random_pet.this.id}-"
}

resource "aws_s3_bucket_ownership_controls" "grading_output" {
  bucket = aws_s3_bucket.grading_output.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "grading_output" {
  depends_on = [aws_s3_bucket_ownership_controls.grading_output]
  bucket     = aws_s3_bucket.grading_output.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# CloudWatch Log Group for Build Logs
# -----------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograding-${random_pet.this.id}"
  retention_in_days = 14
}

# -----------------------------------------------------------------------------
# IAM Role for CodeBuild
# -----------------------------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograding-role-${random_pet.this.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Logging and S3 Access
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-autograding-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.codebuild_logs.arn}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.grading_output.arn,
          "${aws_s3_bucket.grading_output.arn}/*"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# GitHub Source Credential (OAuth or PAT)
# -----------------------------------------------------------------------------
resource "aws_codebuild_source_credential" "github_token" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_access_token
}

# -----------------------------------------------------------------------------
# CodeBuild Project
# -----------------------------------------------------------------------------
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograding-project-${random_pet.this.id}"
  description   = "Build project to run autograding on student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "30"
  queued_timeout = "480"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_output.bucket
    # Packaging results (e.g., grading reports)
    packaging = "ZIP" 
    name      = "grading-results.zip"
  }

  source {
    type     = "GITHUB"
    location = var.github_repo_url

    git_clone_depth     = 1

    auth {
      type     = "OAUTH"
      resource = aws_codebuild_source_credential.github_token.arn
    }
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = var.build_image
    type            = "LINUX_CONTAINER"
    privileged_mode = true # Often required for Docker-based grading containers

    # Environment variables for the build script
    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.grading_output.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-logs"
    }
  }
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------
variable "aws_region" {
  description = "AWS region where resources will be created"
  default     = "us-east-1"
}

variable "github_repo_url" {
  description = "HTTPS URL of the GitHub repository containing student submissions"
  type        = string
  # Example: "https://github.com/my-org/cs101-submissions.git"
}

variable "github_access_token" {
  description = "GitHub Personal Access Token with repo access to fetch submissions"
  type        = string
  sensitive   = true
}

variable "build_image" {
  description = "Docker image used by CodeBuild to execute the grading environment"
  type        = string
  default     = "aws/codebuild/standard:6.0"
  # Could be a custom image containing Python, Java, Docker, etc.
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------
output "project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket storing grading results"
  value       = aws_s3_bucket.grading_output.bucket
}

output "log_group_name" {
  description = "CloudWatch Log Group name"
  value       = aws_cloudwatch_log_group.codebuild_logs.name
}

