}

# ECR DKR Interface Endpoint (for pulling docker layers)
resource "aws_vpc_endpoint" "ecr_dkr_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.ecr.dkr"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  private_dns_enabled = true

  security_group_ids = [aws_security_group.vpc_endpoint_sg.id]

  tags = {
    Name = "autograder-ecr-dkr-endpoint"
  }
}

# --- Security Groups ---

resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for CodeBuild in VPC with no internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress to 0.0.0.0/0 allowed
  egress {
    description = "Allow HTTPS to VPC Endpoints"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  # Egress for S3 Gateway Endpoint (managed by AWS, but often requires broad port 80/443 access or specific rules depending on configuration)
  # Note: S3 Gateway endpoints generally route via the route table, but ENIs need to be able to resolve and route internally.
  egress {
    description = "Allow HTTP to S3"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "autograder-vpc-endpoint-sg"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    description = "Allow HTTPS from CodeBuild SG"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    security_groups = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "autograder-vpc-endpoint-sg"
  }
}

# --- IAM Roles ---

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "codebuild_policy_attach" {
  name       = "autograder-codebuild-policy-attach"
  roles      = [aws_iam_role.codebuild_role.name]
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

# Custom policy for VPC networking
resource "aws_iam_role_policy" "codebuild_vpc_policy" {
  name = "autograder-codebuild-vpc-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# --- Supporting Resources ---

resource "aws_s3_bucket" "artifacts_bucket" {
  bucket = "autograder-artifacts-bucket-unique-id"
}

resource "aws_cloudwatch_log_group" "build_logs" {
  name = "/aws/codebuild/autograder-project"
}

# --- CodeBuild Project ---

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder executing student submissions in an isolated VPC"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "10"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifacts_bucket.bucket
  }

  # Note: In a strictly isolated environment without internet, 
  # pulling directly from GitHub.com requires an external mechanism (like NAT) 
  # or mirroring to S3 first. 
  # This configuration uses GitHub as the source type, but the VPC configuration 
  # strictly blocks internet access. 
  # For full execution, the source would need to be injected or a NAT used with strict SG rules.
  # Assuming source type requested is GitHub.
  source {
    type      = "GITHUB"
    location  = "https://github.com/username/repository.git" # Replace with actual repo
    buildspec = "buildspec.yml"
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:6.0" # Uses ECR, accessible via VPC Endpoint
    type         = "LINUX_CONTAINER"

    # Configure environment variables for grading
    environment_variable {
      name  = "NET_RESTRICTED"
      value = "true"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.build_logs.name
    }
  }

  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id
    subnets = [
      aws_subnet.private_subnet.id
    ]
    security_group_ids = [
      aws_security_group.codebuild_sg.id
    ]
  }
}

