extracted_code:
provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# VPC and Networking
# -----------------------------------------------------------------------------

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Public Subnet for NAT Gateway
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Private Subnet for CodeBuild
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Internet Gateway for Public Subnet
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public_subnet.id

  tags = {
    Name = "autograder-nat"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Route Table for Private Subnet (Traffic goes to NAT for GitHub access)
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# VPC Endpoints (To keep S3 and CloudWatch traffic internal)
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"

  route_table_ids = [
    aws_route_table.private_rt.id
  ]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-logs-endpoint"
  }
}

# Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for CodeBuild in VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Outbound rules
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow HTTPS (GitHub access)"
  }

  egress {
    from_port       = 0
    to_port         = 0
    protocol        = "-1"
    cidr_blocks     = ["0.0.0.0/0"]
    description     = "Allow all outbound for internal VPC traffic (Endpoints)"
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# -----------------------------------------------------------------------------
# S3 Bucket for Grading Outputs
# -----------------------------------------------------------------------------

resource "aws_s3_bucket" "grading_results" {
  bucket = "autograder-submission-results-bucket"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "public_access_block" {
