provider "aws" {
  region = "us-east-1"
}

# Resource: Random ID for unique naming
resource "random_integer" "suffix" {
  min = 1
  max = 99999
}

# -----------------------------------------------------------------------------
# VPC and Networking
# -----------------------------------------------------------------------------

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc-${random_integer.suffix.result}"
  }
}

# Private Subnets for CodeBuild (No Internet Gateway, blocking direct internet access)
resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.autograder_vpc.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "autograder-private-subnet-${count.index}"
  }
}

# Route Table (Local only - No IGW or NAT Gateway routes)
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private_assoc" {
  count          = 2
  subnet_id      = aws_subnet.private_subnets[count.index].id
  route_table_id = aws_route_table.private_rt.id
}

# -----------------------------------------------------------------------------
# VPC Endpoints (Allow CodeBuild to function without Internet Gateway)
# -----------------------------------------------------------------------------

# Interface Endpoints (Required for CodeBuild to communicate with AWS services)
locals {
  endpoint_services = [
    "com.amazonaws.us-east-1.codebuild",
    "com.amazonaws.us-east-1.logs",
    "com.amazonaws.us-east-1.ecr.api",
    "com.amazonaws.us-east-1.ecr.dkr",
    "com.amazonaws.us-east-1.ssm" # Useful for parameters
  ]
}

resource "aws_vpc_endpoint" "interface_endpoints" {
  count = length(local.endpoint_services)

  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = local.endpoint_services[count.index]
  private_dns_enabled = true
  subnet_ids          = aws_subnet.private_subnets[*].id

  security_group_ids = [aws_security_group.vpc_endpoint_sg.id]

  tags = {
    Name = replace(local.endpoint_services[count.index], "com.amazonaws.us-east-1.", "")
  }
}

# Gateway Endpoint for S3
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"

  route_table_ids = [aws_route_table.private_rt.id]

  tags = {
    Name = "s3-endpoint"
  }
}

# -----------------------------------------------------------------------------
# Security Groups
# -----------------------------------------------------------------------------

# Security Group for VPC Endpoints
resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "vpc-endpoint-sg"
  description = "Allow inbound HTTPS from CodeBuild"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    security_groups = [aws_security_group.codebuild_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-sg"
  description = "Security Group for CodeBuild Environment"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No Ingress required from outside
  # No Egress to 0.0.0.0/0 (Internet blocked)
  # Egress allowed only to VPC Interface Endpoints (handled by referencing endpoint SG or CIDR)
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    security_groups = [aws_security_group.vpc_endpoint_sg.id]
  }

  # Allow S3 access via Gateway Endpoint (not SG restricted, but routing based)
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    prefix_list_ids = [aws_vpc_endpoint.s3_endpoint.prefix_list_id]
  }
}

# -----------------------------------------------------------------------------
# S3 Bucket for Artifacts and Outputs
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "autograder-results-${random_integer.suffix.result}"
}

resource "aws_s3_bucket_versioning" "autograder_bucket_versioning" {
  bucket = aws_s3_bucket.autograder_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# -----------------------------------------------------------------------------
# IAM Roles and Policies
# -----------------------------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage",
          "ecr:BatchCheckLayerAvailability"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# -----------------------------------------------------------------------------
# CodeBuild Project
# -----------------------------------------------------------------------------
resource "aws_codebuild_project" "autograder_project" {
  name          = "autograder-project"
  description   = "Build project for autograding student submissions"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_bucket.id
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0" # Or a custom docker image
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # Environment variables (placeholder)
