      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.autograder_bucket.id
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/user/repo.git" # Replace with actual repo
    git_clone_depth = 1

    # In a strictly private VPC without internet, fetching from public GitHub fails.
