resource "aws_s3_bucket" "cat_images" {
  bucket_prefix = "cat-image-store-"
}

# Block public access to the bucket for security (access via API/Lambda only)
resource "aws_s3_bucket_public_access_block" "cat_images_block" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. IAM Role for Lambda
resource "aws_iam_role" "lambda_api_role" {
  name = "cat_api_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
