# 3. Create the Lambda Function Source Code locally
# This Python code handles the upload logic and the random selection logic
locals {
  lambda_script_content = <<EOF
import json
import boto3
import random
import base64

s3_client = boto3.client('s3')
BUCKET_NAME = '${aws_s3_bucket.cat_images.id}'

def lambda_handler(event, context):
    path = event.get('path', '/')
    http_method = event.get('httpMethod')

    # Handle Random Cat Request
    if path == '/random' and http_method == 'GET':
        try:
            response = s3_client.list_objects_v2(Bucket=BUCKET_NAME)
            if 'Contents' not in response:
                return {'statusCode': 404, 'body': json.dumps({'error': 'No cats found'})}

            # Pick a random object
            random_obj = random.choice(response['Contents'])

            # Generate a presigned URL (valid for 1 hour) so the user can view the image
            url = s3_client.generate_presigned_url('get_object', 
                                                    Params={'Bucket': BUCKET_NAME, 'Key': random_obj['Key']},
                                                    ExpiresIn=3600)

            return {
                'statusCode': 200,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'url': url, 'filename': random_obj['Key']})
            }
        except Exception as e:
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    # Handle Upload Request
    if path == '/upload' and http_method == 'POST':
        try:
            body = event.get('body', '')
            is_base64_encoded = event.get('isBase64Encoded', False)

            # Decode body if API Gateway sent it as base64
            if is_base64_encoded:
                file_data = base64.b64decode(body)
            else:
                file_data = body.encode('utf-8')

            # Generate a simple filename (in production, use headers or UUIDs)
            filename = f"cat_{random.randint(10000, 99999)}.jpg"

            s3_client.put_object(Bucket=BUCKET_NAME, Key=filename, Body=file_data, ContentType='image/jpeg')

            return {
                'statusCode': 201,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'message': 'Upload successful', 'filename': filename})
            }
        except Exception as e:
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    return {'statusCode': 400, 'body': json.dumps({'error': 'Invalid route'})}
EOF
}

