data "archive_file" "random_lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/random_lambda.zip"
  source {
    content  = <<-EOF
      import json
      import boto3
      import base64
      import random
      import os

      s3_client = boto3.client('s3')
      BUCKET_NAME = os.environ['BUCKET_NAME']

      def lambda_handler(event, context):
          try:
              # List objects in bucket
              response = s3_client.list_objects_v2(Bucket=BUCKET_NAME)

              if 'Contents' not in response or len(response['Contents']) == 0:
                  return {
                      'statusCode': 404,
                      'body': json.dumps({'message': 'No cats found. Please upload one!'})
                  }

              # Pick a random object
              random_obj = random.choice(response['Contents'])
              key = random_obj['Key']

              # Get the object
              obj_response = s3_client.get_object(Bucket=BUCKET_NAME, Key=key)
              image_data = obj_response['Body'].read()

              # Return base64 encoded image
              return {
                  'statusCode': 200,
                  'headers': {
                      'Content-Type': 'image/jpeg'
                  },
                  'body': base64.b64encode(image_data).decode('utf-8'),
                  'isBase64Encoded': True
              }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': str(e)})
              }
      EOF
    filename = "random_function.py"
  }
}

resource "aws_lambda_function" "random_cat" {
  filename         = data.archive_file.random_lambda_zip.output_path
  function_name    = "RandomCatFunction"
  role             = aws_iam_role.lambda_exec_role.arn
  handler          = "random_function.lambda_handler"
  source_code_hash = data.archive_file.random_lambda_zip.output_base64sha256
  runtime          = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# --- API Gateway ---

resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API to upload and retrieve random cat images"
}

# Resource: /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# Method: POST /upload
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

# Integration: POST /upload -> Upload Lambda
resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_method.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.upload_cat.invoke_arn
}

# Resource: /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# Method: GET /random
resource "aws_api_gateway_method" "random_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration: GET /random -> Random Lambda
resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_method.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.random_cat.invoke_arn
}

# Deployment
resource "aws_api_gateway_deployment" "cat_api_deploy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload_resource.id,
      aws_api_gateway_resource.random_resource.id,
      aws_api_gateway_method.upload_method.id,
      aws_api_gateway_method.random_method.id,
      aws_api_gateway_integration.upload_integration.id,
      aws_api_gateway_integration.random_integration.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "cat_api_stage" {
  deployment_id = aws_api_gateway_deployment.cat_api_deploy.id
