    content  = <<-EOF
      import json
      import boto3
      import base64
      import uuid
      import os

      s3_client = boto3.client('s3')
      BUCKET_NAME = os.environ['BUCKET_NAME']

      def lambda_handler(event, context):
          try:
              # Parse body (API Gateway Proxy Integration)
              body = json.loads(event['body'])
              file_content = base64.b64decode(body['image'])

              # Generate a unique filename
              filename = f"{str(uuid.uuid4())}.jpg"

              # Upload to S3
              s3_client.put_object(Bucket=BUCKET_NAME, Key=filename, Body=file_content)

              return {
                  'statusCode': 200,
                  'body': json.dumps({'message': 'Cat image uploaded successfully', 'filename': filename})
              }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': str(e)})
              }
      EOF
    filename = "upload_function.py"
  }
}

