terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for storing cat images
resource "aws_s3_bucket" "cat_images_bucket" {
  bucket = "cat-images-app-bucket-unique-id"
}

resource "aws_s3_bucket_public_access_block" "cat_images_block" {
  bucket = aws_s3_bucket.cat_images_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. DynamoDB Table for image metadata
resource "aws_dynamodb_table" "cat_metadata_table" {
  name           = "CatImagesTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "ImageId"

  attribute {
    name = "ImageId"
    type = "S"
  }
}

# 3. Lambda Function Logic (Python)
resource "local_file" "lambda_handler" {
  content  = <<EOF
import boto3
import json
import random
import os

s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table_name = os.environ['DYNAMODB_TABLE']
bucket_name = os.environ['S3_BUCKET']
table = dynamodb.Table(table_name)

def lambda_handler(event, context):
    http_method = event['httpMethod']
    path = event['path']

    if http_method == 'POST' and path == '/cats':
        # Upload Logic: Create ID, store in DB, return Presigned URL
        image_id = str(random.randint(10000, 99999))
        file_key = f"{image_id}.jpg"

        table.put_item(Item={'ImageId': image_id, 'FileKey': file_key})

        upload_url = s3_client.generate_presigned_url(
            'put_object',
            Params={'Bucket': bucket_name, 'Key': file_key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'body': json.dumps({'image_id': image_id, 'upload_url': upload_url}),
            'headers': {'Content-Type': 'application/json'}
        }

    elif http_method == 'GET' and path == '/cats/random':
        # Retrieve Logic: Scan DB, pick random, return Presigned GET URL
        response = table.scan()
        items = response.get('Items', [])

        if not items:
            return {'statusCode': 404, 'body': json.dumps({'error': 'No images found'})}

        random_item = random.choice(items)
        file_key = random_item['FileKey']

        download_url = s3_client.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket_name, 'Key': file_key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'body': json.dumps({'image_id': random_item['ImageId'], 'download_url': download_url}),
            'headers': {'Content-Type': 'application/json'}
        }

    return {'statusCode': 400, 'body': json.dumps({'error': 'Invalid request'})}
EOF
  filename = "${path.module}/lambda_function.py"
}

# 4. Archive the Lambda code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 5. IAM Role for Lambda
