provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Network Data Sources (Using Default VPC)
# ---------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# ---------------------------------------------------------
# 2. EC2 Key Pair
# ---------------------------------------------------------
resource "tls_private_key" "generated" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "generated" {
  key_name   = "terraform-backup-key"
  public_key = tls_private_key.generated.public_key_openssh
}

resource "local_file" "private_key" {
  content  = tls_private_key.generated.private_key_pem
  filename = "terraform-backup-key.pem"
  file_permission = "0400"
}

# ---------------------------------------------------------
# 3. Security Group
# ---------------------------------------------------------
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# ---------------------------------------------------------
# 4. IAM Role for AWS Backup
# ---------------------------------------------------------
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_default_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# ---------------------------------------------------------
# 5. EC2 Instance
# ---------------------------------------------------------
resource "aws_instance" "web_server" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  key_name               = aws_key_pair.generated.key_name
  subnet_id              = data.aws_subnets.default.ids[0]
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  tags = {
    Name        = "WebServer-WithBackup"
    Environment = "Production"
    Backup      = "Daily" # This tag identifies the instance for the backup plan
  }
}

# ---------------------------------------------------------
# 6. AWS Backup Vault
# ---------------------------------------------------------
resource "aws_backup_vault" "daily_vault" {
  name = "ec2-daily-backup-vault"
}

# ---------------------------------------------------------
# 7. AWS Backup Plan (Scheduled at 12:00 AM)
# ---------------------------------------------------------
resource "aws_backup_plan" "daily_plan" {
  name = "ec2-daily-backup-plan"

  rule {
    rule_name         = "rule_12am_daily"
    target_vault_name = aws_backup_vault.daily_vault.name

    # Schedule: Cron expression for 12:00 AM UTC daily
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7 # Keep backups for 7 days
    }
  }
}

# ---------------------------------------------------------
# 8. AWS Backup Selection
# ---------------------------------------------------------
resource "aws_backup_selection" "daily_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-daily-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  # Selects resources with the tag "Backup" = "Daily"
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

