    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_security_group" "instance_sg" {
  name_prefix = "streaming-instance-"
  description = "Security group for EC2 instances"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict SSH to VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    create_before_destroy = true
  }
}

# ---------------------------------------------------------
# Application Load Balancer
# ---------------------------------------------------------
resource "aws_lb" "streaming_lb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-streaming-alb"
  }
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# ---------------------------------------------------------
# EC2 Instances & Auto Scaling
# ---------------------------------------------------------
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_launch_template" "streaming_lt" {
  name_prefix            = "streaming-"
  image_id               = data.aws_ami.amazon_linux_2.id
  instance_type          = "t3.medium"
  key_name               = var.ssh_key_name
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  monitoring {
    enabled = true
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y nginx aws-cli
              systemctl start nginx
              systemctl enable nginx

              # Create a simple streaming placeholder page
              cat > /usr/share/nginx/html/index.html <<'EOHTML'
              <html>
              <head><title>Video Streaming Platform</title></head>
              <body>
              <h1>Video Streaming Node</h1>
              <p>Server reachable via Load Balancer.</p>
              </body>
              </html>
              EOHTML
              EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "streaming-server"
    }
  }
}

resource "aws_autoscaling_group" "streaming_asg" {
  desired_capacity    = 2
  max_size            = 6
  min_size            = 2
  vpc_zone_identifier = module.vpc.private_subnets
  target_group_arns   = [aws_lb_target_group.streaming_tg.arn]

  launch_template {
    id      = aws_launch_template.streaming_lt.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-asg-instance"
    propagate_at_launch = true
  }
}

# ---------------------------------------------------------
# Route 53 DNS
# ---------------------------------------------------------
resource "aws_route53_record" "streaming_dns" {
  zone_id = var.hosted_zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_lb.streaming_lb.dns_name
    zone_id                = aws_lb.streaming_lb.zone_id
    evaluate_target_health = true
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------
output "load_balancer_url" {
  description = "URL of the Load Balancer"
  value       = aws_lb.streaming_lb.dns_name
}

output "streaming_domain" {
  description = "Full domain name configured in Route 53"
  value       = "http://${var.domain_name}"
}

output "s3_bucket_name" {
  description = "Name of the S3 bucket storing video assets"
  value       = aws_s3_bucket.video_assets.id
}
