  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

# LB Target Group Attachment
resource "aws_lb_target_group_attachment" "attach" {
  target_group_arn = aws_lb_target_group.main.arn
  target_id        = aws_instance.web.id
