```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC Resource
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Internet Gateway for Public Subnets
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Public Subnets (Required for DB Subnet Group)
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Database Access Security Group
resource "aws_security_group" "db_access" {
  name        = "db-access-sg"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL access from VPC"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-access-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Random Password for DB
resource "random_password" "password" {
  length           = 16
  special          = true
  override_special = "_!%@" # Override to avoid characters that might cause shell issues
}

# RDS MySQL Instance
resource "aws_db_instance" "default" {
  identifier             = "mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.4.3"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20 # Note: AWS RDS MySQL requires a minimum of 20GB for gp2/gp3 storage
  storage_type           = "gp2"
  db_name                = "mydb"
  username               = "admin"
  password               = random_password.password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  publicly_accessible    = false # Best practice: accessible via VPC only
  skip_final_snapshot    = true
  parameter_group_name   = "default.mysql8.4"

  tags = {
    Name = "mysql-8-4-instance"
  }
}

output "db_endpoint" {
  description = "The endpoint of the database"
  value       = aws_db_instance.default.endpoint
}
