provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking Configuration
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "protected-postgres-vpc"
  }
}

# Fetch available availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Private Subnets
resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.main_vpc.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "private-subnet-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id

  tags = {
    Name = "Postgres Subnet Group"
  }
}

# 2. Security Group
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Security group for protected PostgreSQL RDS"
  vpc_id      = aws_vpc.main_vpc.id

  # Allow PostgreSQL traffic only from within the VPC (or specific CIDRs)
  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main_vpc.cidr_block]
  }

  # Egress rule (usually necessary for OS patching and package updates if internet access is configured via NAT or Gateway)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# 3. KMS Encryption Key
resource "aws_kms_key" "postgres_kms_key" {
  description             = "Customer-managed key for PostgreSQL RDS encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "postgres-rds-key"
  }
}

# 4. Custom Parameter Group
resource "aws_db_parameter_group" "custom_postgres_pg" {
  name        = "custom-postgres-pg"
  family      = "postgres15" # Note: Ensure this matches the engine version below
  description = "Custom parameter group for PostgreSQL"

  # Example of a custom parameter
  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

# 5. RDS Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "protected-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium"
  allocated_storage      = 50
  storage_type           = "gp2"

  # Database Credentials
  username               = "dbadmin"
  password               = "SecurePassword123!" # In production, use aws_secretsmanager_secret or similar

  # Network & Security
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = false

  # High Availability & Encryption
  multi_az               = true
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.postgres_kms_key.arn

  # Configuration
  parameter_group_name   = aws_db_parameter_group.custom_postgres_pg.name
  skip_final_snapshot    = false
  final_snapshot_identifier = "postgres-final-snapshot"
  deletion_protection    = true

  # Maintenance
  maintenance_window     = "Mon:03:00-Mon:04:00"
  backup_window          = "03:00-04:00"
  backup_retention_period = 7

  # Performance Insights
  performance_insights_enabled = true

  tags = {
    Name = "ProtectedPostgreSQLRDS"
  }
}

