provider "aws" {
  region = "us-east-1"
}

# --- Network Infrastructure ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-subnet-b"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# --- Security ---

resource "aws_security_group" "rds" {
  name        = "postgres-sg"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# --- KMS Encryption ---

resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10

  tags = {
    Name = "rds-postgres-key"
  }
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds.key_id
}

# --- Database Parameters ---

resource "aws_db_parameter_group" "postgres15" {
  name   = "custom-postgres15-pg"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  tags = {
    Name = "Custom PostgreSQL 15 Parameter Group"
  }
}

# --- Random Password ---

resource "random_password" "password" {
  length  = 16
  special = true
}

# --- RDS Instance ---

resource "aws_db_instance" "postgres" {
  identifier             = "secure-postgres-15"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium"
  allocated_storage      = 50
  storage_type           = "gp3"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds.arn
  db_name                = "mydb"
  username               = "adminuser"
  password               = random_password.password.result

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  parameter_group_name   = aws_db_parameter_group.postgres15.name
  multi_az               = true

  backup_retention_period = 7
  skip_final_snapshot    = false
  final_snapshot_identifier = "postgres-final-snapshot"

  tags = {
    Name        = "PostgreSQL-15-Secure"
    Environment = "Production"
  }
}
