      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@" 
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

# Create Internet Gateway for public subnets
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "airbyte-test-igw"
  }
}

# Create Public Subnets (RDS requires subnets in at least 2 AZs)
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Create Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-public-rt"
  }
}

# Associate Route Table with Public Subnets
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "airbyte-rds-sg"
  description = "Allow PostgreSQL inbound traffic for Airbyte tests"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access from anywhere"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier             = "airbyte-test-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium"
  allocated_storage      = 500
  storage_type           = "gp3"
  storage_encrypted      = true
  db_name                = "airbyte"
  username               = "adminuser"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true
  multi_az               = false # Set to true for higher availability in production
  skip_final_snapshot    = true  # Useful for test workloads to avoid deletion errors

  # Backup and Maintenance
  backup_retention_period = 1
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:00-Mon:05:00"

  # Performance Insights for monitoring (managed feature)
  performance_insights_enabled = true

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = "test"
  }
}

output "rds_endpoint" {
  description = "RDS Instance Endpoint"
  value       = aws_db_instance.postgres.endpoint
}

output "db_password" {
  description = "Database Master Password"
  value       = random_password.db_password.result
  sensitive   = true
}

