  instance_class         = "db.t3.medium"
  allocated_storage      = 500
  storage_type           = "gp3"
  storage_encrypted      = true
  db_name                = "airbyte"
  username               = "adminuser"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true
  multi_az               = false # Set to true for higher availability in production
  skip_final_snapshot    = true  # Useful for test workloads to avoid deletion errors

  # Backup and Maintenance
  backup_retention_period = 1
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:00-Mon:05:00"

  # Performance Insights for monitoring (managed feature)
  performance_insights_enabled = true

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = "test"
  }
}

output "rds_endpoint" {
  description = "RDS Instance Endpoint"
  value       = aws_db_instance.postgres.endpoint
}

output "db_password" {
  description = "Database Master Password"
  value       = random_password.db_password.result
  sensitive   = true
}
