provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the RDS instance
resource "random_password" "rds_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Retrieve the default VPC
data "aws_vpc" "default" {
  default = true
}

# Retrieve subnets in the default VPC for the DB Subnet Group
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "rds-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Create a Security Group that allows public access on port 3306
resource "aws_security_group" "rds_sg" {
  name        = "rds-public-access-sg"
  description = "Allow public inbound MySQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-public-access-sg"
  }
}

# Provision the AWS RDS MySQL instance
resource "aws_db_instance" "default" {
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "mydb"
  username               = "admin"
  password               = random_password.rds_password.result
  parameter_group_name   = "default.mysql8.0"
  skip_final_snapshot    = true
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.default.name

  tags = {
    Name = "MyMySQLInstance"
  }
}

# Output the generated password
output "rds_instance_password" {
  description = "The password for the RDS instance"
  value       = random_password.rds_password.result
  sensitive   = true
}

