extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# VPC and Networking
# ---------------------------------------------------------
resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.this.id
  cidr_block        = cidrsubnet(aws_vpc.this.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-private-subnet-${count.index}"
  }
}

# ---------------------------------------------------------
# Security Groups
# ---------------------------------------------------------
# Security Group for the RDS Proxy
resource "aws_security_group" "proxy" {
  name_prefix = "proxy-sg-"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Example: Allow internal apps
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds.id]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Security Group for Aurora RDS
resource "aws_security_group" "rds" {
  name_prefix = "rds-sg-"
  description = "Security group for Aurora MySQL"
  vpc_id      = aws_vpc.this.id

  # Only allow traffic from the Proxy Security Group
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

# ---------------------------------------------------------
# Database Subnet Group
# ---------------------------------------------------------
resource "aws_db_subnet_group" "this" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

# ---------------------------------------------------------
# Secrets Manager
# ---------------------------------------------------------
resource "random_password" "db_password" {
  length  = 16
  special = true
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-mysql-secret"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# ---------------------------------------------------------
# IAM Role for RDS Proxy
# ---------------------------------------------------------
data "aws_iam_policy_document" "proxy_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["rds.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "proxy" {
  name               = "rds-proxy-role"
  assume_role_policy = data.aws_iam_policy_document.proxy_assume_role.json
}

data "aws_iam_policy_document" "proxy_policy" {
  statement {
    sid = "SecretsManagerAccess"
    effect = "Allow"

    actions = [
      "secretsmanager:GetSecretValue",
      "secretsmanager:DescribeSecret"
    ]

    resources = [aws_secretsmanager_secret.db_credentials.arn]
  }

  statement {
    sid = "KMSDecryption"
    effect = "Allow"

    actions = [
      "kms:Decrypt"
    ]

    # If using default KMS for secrets, this ARN might need adjustment. 
    # For this example, we omit specific KMS ARNs if not created, 
    # but typically Secret ARN implies permission if key policy allows.
    # Adding specific resource if KMS key was used:
    # resources = ["arn:aws:kms:..."] 
  }

  statement {
    sid = "CloudWatchLogs"
    effect = "Allow"

    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "logs:DescribeLogStreams"
    ]

    resources = ["arn:aws:logs:*:*:*"]
  }
}

resource "aws_iam_role_policy" "proxy" {
  name   = "rds-proxy-policy"
  role   = aws_iam_role.proxy.id
  policy = data.aws_iam_policy_document.proxy_policy.json
}

# ---------------------------------------------------------
# Aurora MySQL Cluster
# ---------------------------------------------------------
resource "aws_rds_cluster" "this" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  database_name           = "mydb"
  master_username         = "admin"
  master_secret_arn       = aws_secretsmanager_secret.db_credentials.arn

  db_subnet_group_name    = aws_db_subnet_group.this.name
  vpc_security_group_ids  = [aws_security_group.rds.id]

  skip_final_snapshot     = true
  backup_retention_period = 1

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "this" {
  count              = 1
  identifier         = "aurora-mysql-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.this.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.this.engine
  engine_version     = aws_rds_cluster.this.engine_version
  publicly_accessible = false
}

# ---------------------------------------------------------
# RDS Proxy
# ---------------------------------------------------------
resource "aws_db_proxy" "this" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]
  role_arn               = aws_iam_role.proxy.arn
  auth {
    auth_scheme = "SECRETS"
    secret_arn  = aws_secretsmanager_secret.db_credentials.arn
    iam_auth    = "DISABLED"
  }

  depends_on = [ aws_iam_role_policy.proxy ]
}

# Note: Terraform provider does not support linking RDS Proxy to specific RDS resources directly via a resource attribute.
# This must be done via the AWS CLI or Console after creation, or via a local-exec provisioner as shown below.

resource "null_resource" "register_proxy_targets" {
  depends_on = [
    aws_db_proxy.this,
    aws_rds_cluster_instance.this
  ]

  provisioner "local-exec" {
    command = <<-EOT
      aws rds register-db-proxy-targets \n        --db-proxy-name ${aws_db_proxy.this.name} \n        --db-cluster-identifiers ${aws_rds_cluster.this.cluster_identifier}
    EOT
  }
}

