```hcl
provider "aws" {
  region = "us-east-1"
}

provider "random" {}

# -----------------------------------------------------------------------------
# 1. Networking Infrastructure (VPC, Subnets, Security Groups)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "db_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-db-subnet-${count.index + 1}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.db_subnet[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Group for the Aurora Cluster
resource "aws_security_group" "aurora_sg" {
  name_prefix = "aurora-sg-"
  vpc_id      = aws_vpc.main.id

  # Only allow traffic from the RDS Proxy Security Group
  ingress {
    from_security_group_id = aws_security_group.proxy_sg.id
    to_port     = 3306
    protocol    = "tcp"
    from_port   = 3306
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-security-group"
  }
}

# Security Group for the RDS Proxy
resource "aws_security_group" "proxy_sg" {
  name_prefix = "proxy-sg-"
  vpc_id      = aws_vpc.main.id

  # Allow access from within the VPC (e.g., application servers)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "proxy-security-group"
  }
}

# -----------------------------------------------------------------------------
# 2. Secrets Management
# -----------------------------------------------------------------------------

resource "random_password" "db_password" {
  length  = 16
  special = true
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-mysql-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# -----------------------------------------------------------------------------
# 3. IAM Roles for RDS Proxy
# -----------------------------------------------------------------------------

resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_secret_policy" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRDSDataFullAccess" 
}

# -----------------------------------------------------------------------------
# 4. Aurora MySQL Cluster
# -----------------------------------------------------------------------------

resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.08.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_secret_arn     = aws_secretsmanager_secret.db_credentials.arn
  db_cluster_instance_class = "db.serverless" # Using Serverless v2 or t3 requires instance class definition in newer versions, but cluster level controls general params.

  # For Provisioned mode (not Serverless v2), you define instances separately.
  # We will create instances below, so we omit availability_zones here if creating specific instances.

  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.main.name

  skip_final_snapshot = true
  storage_encrypted   = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 1
  identifier         = "aurora-instance-${count.index + 1}"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora_cluster.engine
  engine_version     = aws_rds_cluster.aurora_cluster.engine_version

  publicly_accessible = false
  db_subnet_group_name   = aws_db_subnet_group.main.name
}

# -----------------------------------------------------------------------------
# 5. RDS Proxy
# -----------------------------------------------------------------------------

resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.db_subnet[*].id
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth   = "DISABLED"
  }

  requires_tls = false

  depends_on = [
    aws_rds_cluster_instance.aurora_instances
  ]
}

resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

resource "aws_db_proxy_target" "aurora_target" {
  db_cluster_identifier = aws_rds_cluster.aurora_cluster.id
  db_proxy_name         = aws_db_proxy.aurora_proxy.name
  target_group_name     = aws_db_proxy_default_target_group.default.name
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "proxy_endpoint" {
  description = "The endpoint of the RDS Proxy"
  value       = aws_db_proxy.aurora_proxy.endpoint
}

output "cluster_endpoint" {
  description = "The writer endpoint of the Aurora Cluster"
  value       = aws_rds_cluster.aurora_cluster.endpoint
}

output "secret_arn" {
  description = "The ARN of the secret storing credentials"
  value       = aws_secretsmanager_secret.db_credentials.arn
}
