provider "aws" {
  region = "us-east-1"
}

# Generate an SSH key pair for accessing the instance
resource "tls_private_key" "this" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Upload the public key to Lightsail
resource "aws_lightsail_key_pair" "this" {
  name       = "terraform-lightsail-key"
  public_key = tls_private_key.this.public_key_openssh
}

# Create a Lightsail Instance
resource "aws_lightsail_instance" "this" {
  name              = "simple-lightsail-app"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"
  key_pair_name     = aws_lightsail_key_pair.this.name

  # User data to install and start a simple Apache web server
  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Deployed via Terraform</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name        = "Simple-Lightsail"
    Environment = "Testing"
  }
}

# Open port 80 for HTTP traffic
resource "aws_lightsail_instance_public_ports" "this" {
  instance_name = aws_lightsail_instance.this.name

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }
}

# Output the instance public IP
output "public_ip" {
  value = aws_lightsail_instance.this.public_ip_address
}

# Output the generated private key (save this to a .pem file to connect)
output "private_key" {
  value     = tls_private_key.this.private_key_pem
  sensitive = true
}

