# Note: The aws_lightsail_instance resource does not currently support the 
# native "Automatic Snapshot" add-on argument within the Terraform provider. 
# To satisfy the requirement of "automatic snapshots turned on", this configuration 
# utilizes AWS Backup, which is the standard method for automating backups across 
# AWS services via Terraform.

resource "aws_lightsail_instance" "example" {
  name              = "lightsail-auto-backup-example"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # Tag the instance to be selected by the AWS Backup plan
  tags = {
    Name       = "lightsail-example"
    AutoBackup = "true"
  }
}

# IAM Role required by AWS Backup to manage the Lightsail instance snapshots
resource "aws_iam_role" "backup_role" {
  name = "lightsail_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS Backup managed policy to the role
resource "aws_iam_role_policy_attachment" "backup_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# Create a Backup Vault to store the snapshots
resource "aws_backup_vault" "example" {
  name = "lightsail_backup_vault"
}

# Define the Backup Plan (Schedule: Daily at 5 AM UTC, Retention: 7 days)
resource "aws_backup_plan" "example" {
  name = "lightsail_daily_plan"

  rule {
    rule_name         = "daily_lightsail_backup"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 5 ? * *)"

    lifecycle {
      delete_after = 7
    }
  }

  # Attach the IAM role created above
  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2" # Lightsail instances are backed up as EC2 resources
  }
}

# Assign the Lightsail instance to the Backup Plan using tags
resource "aws_backup_selection" "example" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "lightsail_backup_selection"
  plan_id      = aws_backup_plan.example.id

  resources = []

  selection_tag {
    type  = "STRING_EQUALS"
    key   = "AutoBackup"
    value = "true"
  }
}

