provider "aws" {
  region = "us-east-1"
}

# Data source to get current region
data "aws_region" "current" {}

# Random suffix for unique naming
resource "random_pet" "suffix" {}

# -----------------------------------------------------------------------------
# S3 Bucket Configuration
# -----------------------------------------------------------------------------

resource "aws_s3_bucket" "this" {
  bucket = "lightsail-bucket-${random_pet.suffix.id}"
}

resource "aws_s3_bucket_ownership_controls" "this" {
  bucket = aws_s3_bucket.this.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "this" {
  depends_on = [aws_s3_bucket_ownership_controls.this]
  bucket     = aws_s3_bucket.this.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# IAM Configuration for Lightsail Access
# Note: Terraform's aws_lightsail_instance resource does not currently support 
# direct IAM role attachment. We create an IAM User with Access Keys 
# and inject them via User Data.
# -----------------------------------------------------------------------------

resource "aws_iam_policy" "s3_access" {
  name        = "LightsailS3AccessPolicy"
  description = "Policy allowing access to the specific S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.this.arn,
          "${aws_s3_bucket.this.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_user" "lightsail_user" {
  name = "lightsail-instance-user-${random_pet.suffix.id}"
  path = "/lightsail/"
}

resource "aws_iam_user_policy_attachment" "attach_policy" {
  user       = aws_iam_user.lightsail_user.name
  policy_arn = aws_iam_policy.s3_access.arn
}

resource "aws_iam_access_key" "lightsail_user_key" {
  user = aws_iam_user.lightsail_user.name
}

# -----------------------------------------------------------------------------
# Lightsail Instance Configuration
# -----------------------------------------------------------------------------

resource "aws_lightsail_instance" "this" {
  name              = "lightsail-s3-instance"
  availability_zone = "${data.aws_region.current.name}a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # User Data script to configure AWS CLI with the IAM User credentials
  user_data = <<-EOF
              #!/bin/bash
              # Install AWS CLI
              yum install -y aws-cli

              # Configure AWS CLI default profile
              aws configure set aws_access_key_id ${aws_iam_access_key.lightsail_user_key.id}
              aws configure set aws_secret_access_key ${aws_iam_access_key.lightsail_user_key.secret}
              aws configure set default.region ${data.aws_region.current.name}

              echo "AWS CLI configured for S3 access."
              EOF

  tags = {
    Name = "LightsailS3Example"
  }
}
```

