provider "aws" {
  region = "us-east-1"
}

# Create an S3 Bucket to serve as the origin
resource "aws_s3_bucket" "origin" {
  bucket = "my-lightsail-distribution-origin-bucket"
}

# Configure the S3 Bucket to be publicly readable
# Note: Lightsail Distributions currently require the S3 origin to be publicly accessible
# as they do not support Origin Access Identities (OAIs) like standard CloudFront.
resource "aws_s3_bucket_public_access_block" "origin" {
  bucket = aws_s3_bucket.origin.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_policy" "origin" {
  bucket = aws_s3_bucket.origin.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.origin.arn}/*"
      },
    ]
  })
}

# Create the Lightsail Distribution
resource "aws_lightsail_distribution" "example" {
  name        = "example-distribution"
  bundle_id   = "small_1_0"
  region_name = "us-east-1"
  is_enabled  = true

  # Define the origin (S3 Bucket)
  origin {
    name        = "s3-origin"
    region_name = "us-east-1"

    # Configuration specific to S3 origins
    s3_bucket_config {
      bucket_name     = aws_s3_bucket.origin.id
      protocol_policy = "http-only"
    }
  }

  # Default cache behavior
  default_cache_behavior {
    behavior = "default"
  }

  # Cache behavior settings (optional)
  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    minimum_ttl          = 0
    maximum_ttl          = 31536000
    forwarded_cookies {
      cookies_allow = ["none"]
      option        = "none"
    }
    forwarded_headers {
      headers_allow = ["*"] # Forward all host headers
    }
    forwarded_query_strings {
      option = false
    }
  }

  # Optional: Add a certificate if using a custom domain
  # certificate_name = "my-certificate"
}

