provider "aws" {
  region = "us-east-1"
}

# Resource 1: Lightsail Instance (The Origin)
# This acts as the backend web server for the distribution.
resource "aws_lightsail_instance" "origin_instance" {
  name              = "origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # User data to install a simple web server for testing
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Served from Lightsail Instance Origin</h1>" > /var/www/html/index.html
              EOF
}

# Resource 2: Instance Networking
# Ensure port 80 is open so the Distribution can pull content.
resource "aws_lightsail_instance_public_ports" "http_open" {
  instance_name = aws_lightsail_instance.origin_instance.name

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }
}

# Resource 3: Lightsail Certificate
# Required for HTTPS support on the Distribution.
# Note: You must validate the domain ownership via DNS validation in Route 53.
resource "aws_lightsail_certificate" "dist_cert" {
  name        = "my-distribution-cert"
  domain_name = "example.com" 
  # subject_alternative_names = ["www.example.com"]
}

# Resource 4: Lightsail Distribution
# Configures the CDN using the instance as the origin.
resource "aws_lightsail_distribution" "cdn" {
  name        = "my-lightsail-distribution"
  bundle_id   = "small_2_0" 
  is_enabled  = true

  # Attach the SSL certificate
  certificate_name = aws_lightsail_certificate.dist_cert.name

  # Origin Configuration
  # Links the distribution to the instance created above.
  origin {
    name            = "origin-instance"
    region_name     = "us-east-1"
    protocol_policy = "http-only" 
  }

  # Default Cache Behavior
  default_cache_behavior {
    behavior = "default"
  }

  # Cache Settings
  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,POST,PATCH,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    forwarded_cookies    {
      cookies_allow = "*"
      option        = "allow"
    }
    forwarded_headers {
      headers_allow = ["*"]
      option        = "allow"
    }
    forwarded_query_strings {
      option = true
    }
  }
}

