  bucket = aws_s3_bucket.backup_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backup_encryption" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "backup_public_access_block" {
  bucket = aws_s3_bucket.backup_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "backup_lifecycle" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    id     = "long-term-retention-rule"
    status = "Enabled"

    # Transition to Standard-IA after 30 days (Infrequent Access)
    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    # Transition to Glacier Flexible Retrieval after 90 days
    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    # Transition to Glacier Deep Archive after 180 days (Lowest cost)
    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    # Expire non-current versions after 5 years to save costs on old backups
    noncurrent_version_expiration {
      noncurrent_days = 1825
    }
  }
}

resource "aws_s3_bucket_object_lock_configuration" "backup_object_lock" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      years = 1 # Retain objects for at least 1 year
    }
  }
}

# Output the bucket name and ARN
