        'statusCode': 200,
        'body': 'Hello from Lambda behind ALB!'
    }
EOF
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "test" {
  filename         = data.aws_archive_file.lambda_zip.output_path
  function_name    = "alb-target-lambda"
  role            = aws_iam_role.lambda.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.aws_archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.9"

  depends_on = [aws_iam_role_policy_attachment.lambda_basic]
}

# --- Load Balancer and Target Group ---

# Application Load Balancer
resource "aws_lb" "main" {
  name               = "lambda-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Environment = "production"
  }
}

# Target Group configured for Lambda
resource "aws_lb_target_group" "lambda" {
  name        = "lambda-target-group"
  target_type = "lambda"

  depends_on = [aws_lb.main]
}

# Permission for ALB to invoke Lambda
resource "aws_lambda_permission" "allow_lb" {
  statement_id  = "AllowExecutionFromLoadBalancer"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.test.function_name
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = aws_lb_target_group.lambda.arn
}

# Attach Lambda to Target Group
resource "aws_lb_target_group_attachment" "test" {
  target_group_arn = aws_lb_target_group.lambda.arn
  target_id        = aws_lambda_function.test.arn
  depends_on       = [aws_lambda_permission.allow_lb]
}

# Listener to forward traffic to the Lambda Target Group
