terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "simple-sql-vpc"
  }
}

# Get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create two subnets in different AZs (Required for RDS Subnet Group)
resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "simple-sql-subnet-${count.index + 1}"
  }
}

# Create an Internet Gateway for public access (simplified for this example)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "simple-sql-igw"
  }
}

# Create a Route Table
resource "aws_route_table" "rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "simple-sql-rt"
  }
}

# Associate subnets with the Route Table
resource "aws_route_table_association" "rta" {
  count          = 2
  subnet_id      = aws_subnet.subnets[count.index].id
  route_table_id = aws_route_table.rt.id
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "simple-sql-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Create a Security Group to allow access to the database
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL access"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: For demo purposes only. Restrict IP in production.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# Create the RDS Instance
resource "aws_db_instance" "default" {
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "simpledb"
  username               = "admin"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true # WARNING: For demo purposes only.
  skip_final_snapshot    = true  # Set to false to retain snapshots on destroy
  parameter_group_name   = "default.mysql8.0"

  tags = {
    Name = "simple-sql-instance"
  }
}

# Output the database endpoint
output "db_endpoint" {
  description = "The connection endpoint for the database"
  value       = aws_db_instance.default.endpoint
}

output "db_username" {
  description = "The master username for the database"
  value       = aws_db_instance.default.username
  sensitive   = true
}

output "db_password" {
  description = "The master password for the database"
  value       = random_password.db_password.result
  sensitive   = true
}

