terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Data source for available availability zones
data "aws_availability_zones" "available" {}

# VPC for the database infrastructure
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sql-db-vpc"
  }
}

# Subnets (spread across AZs for RDS requirements)
resource "aws_subnet" "db_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.main_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "sql-db-subnet-${count.index + 1}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "sql-db-subnet-group"
  subnet_ids = aws_subnet.db_subnets[*].id

  tags = {
    Name = "SQL DB Subnet Group"
  }
}

# Security Group for database access
resource "aws_security_group" "db_sg" {
  name        = "sql-db-sg"
  description = "Allow inbound SQL traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    description = "MySQL access"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "sql-db-sg"
  }
}

# Primary Database Instance
resource "aws_db_instance" "primary" {
  identifier             = "primary-sql-db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_name                = "primarydb"
  username               = "adminuser"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  backup_retention_period = 7

  tags = {
    Name = "Primary SQL Database"
  }
}

# Read Replica (Duplicate of the Primary)
resource "aws_db_instance" "replica" {
  identifier          = "replica-sql-db"
  replicate_source_db = aws_db_instance.primary.identifier
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true

  # Note: Most settings like engine, storage, and username are inherited from the source

  tags = {
    Name = "Replica SQL Database"
  }
}

