  }
}

provider "aws" {
  region = "us-east-1"
}

variable "snapshot_identifier" {
  description = "The identifier for the DB snapshot to restore from."
  type        = string
  default     = "my-existing-snapshot"
}

variable "instance_class" {
  description = "The instance type of the RDS instance."
  type        = string
  default     = "db.t3.micro"
}

variable "db_name" {
  description = "The name of the database to create when restoring."
  type        = string
  default     = "myrestoreddb"
}

resource "aws_db_instance" "this" {
  # General Information
  identifier             = "restored-db-instance"
  instance_class         = var.instance_class
  snapshot_identifier    = var.snapshot_identifier

  # Important: The engine must match the engine of the snapshot
  engine                 = "mysql"
  engine_version         = "8.0"

  # Storage
  # Note: allocated_storage is optional when restoring from a snapshot, 
  # but defaults to the snapshot's storage size.
  storage_type           = "gp2"

  # Credentials & Security
  # Username and password are not required if restoring from a snapshot,
  # they will be imported from the snapshot.
  publicly_accessible    = false

  # Maintenance & Monitoring
  skip_final_snapshot    = true
  apply_immediately      = true

  tags = {
    Name        = "Restored-RDS-Instance"
    Environment = "Restored"
  }
}

