extracted_code:
provider "aws" {
  region = "us-east-1"
}

variable "db_identifier" {
  default = "restored-db-instance"
}

variable "db_username" {
  default = "admin"
}

variable "db_password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "s3_bucket_name" {
  description = "The S3 bucket containing the database backup files"
  type        = string
}

variable "s3_prefix" {
  description = "Prefix inside the S3 bucket where the backup is stored"
  default     = ""
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB Subnet Group"
  type        = list(string)
}

variable "vpc_id" {
  description = "VPC ID for the Security Group"
  type        = string
}

# IAM Role for RDS to access the S3 bucket
resource "aws_iam_role" "rds_s3_import_role" {
  name = "${var.db_identifier}-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy granting read access to the specific S3 bucket
resource "aws_iam_role_policy" "s3_read_policy" {
  name = "${var.db_identifier}-s3-read-policy"
  role = aws_iam_role.rds_s3_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      }
    ]
  })
}

# DB Subnet Group (Required for RDS in VPC)
resource "aws_db_subnet_group" "main" {
  name       = "${var.db_identifier}-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "${var.db_identifier}-subnet-group"
  }
}

# Security Group for the Database
resource "aws_security_group" "rds_sg" {
  name        = "${var.db_identifier}-sg"
  description = "Security group for restored RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.db_identifier}-sg"
  }
}

# RDS Instance with S3 Import Configuration
resource "aws_db_instance" "default" {
  identifier             = var.db_identifier
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = var.db_username
  password               = var.db_password
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  backup_retention_period = 0

  # Configuration block for restoring from S3
  s3_import {
    bucket_name           = var.s3_bucket_name
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
    prefix                = var.s3_prefix
    source_engine         = "mysql"
    source_engine_version = "5.7"
  }

  tags = {
    Name = var.db_identifier
  }
}

