provider "aws" {
  region = "us-east-1"
}

# Retrieve the default VPC
data "aws_vpc" "default" {
  default = true
}

# Retrieve subnets within the default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a DB subnet group
resource "aws_db_subnet_group" "default" {
  name       = "example-db-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "Example DB Subnet Group"
  }
}

# Create a Security Group for the database
resource "aws_security_group" "example" {
  name        = "example-db-sg"
  description = "Allow database inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "MySQL access from within VPC"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "example-db-sg"
  }
}

# Generate a random password for the database
resource "random_password" "password" {
  length  = 16
  special = true
}

# Create the RDS MySQL Instance with Automatic Storage Scaling
resource "aws_db_instance" "example" {
  identifier             = "example-autoscale-db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"

  # Storage Configuration
  allocated_storage      = 20              # Initial storage size (GB)
  max_allocated_storage  = 100             # Maximum storage limit (enables autoscaling)
  storage_type           = "gp3"
  storage_encrypted      = true

  # Authentication
  db_name                = "exampledb"
  username               = "adminuser"
  password               = random_password.password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.example.id]

  # Other settings
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false

  tags = {
    Name = "Example DB with Autoscaling"
  }
}

