provider "aws" {
  region = "us-east-1"
}

# --- Networking Resources ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "tf-db-vpc"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_subnet" "main" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "tf-db-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "tf-db-subnet-group"
  subnet_ids = aws_subnet.main[*].id

  tags = {
    Name = "My DB subnet group"
  }
}

resource "aws_security_group" "main" {
  name        = "rds-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Database with Secrets Management ---
resource "aws_db_instance" "default" {
  identifier             = "tf-database-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true
  db_name                = "mydb"
  username               = "admin"

  # Configures AWS RDS to manage the master user password in AWS Secrets Manager
  manage_master_user_password = true

  # Explicitly sets the KMS key to the default AWS Secrets Manager key
  master_user_secret_kms_key_id = "alias/aws/secretsmanager"

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.main.id]
  publicly_accessible    = false
  skip_final_snapshot    = true
}

