provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Designated KMS Key
# -----------------------------------------------------------------------------
resource "aws_kms_key" "db_creds_key" {
  description             = "KMS key for securing database master credentials"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

resource "aws_kms_alias" "db_creds_alias" {
  name          = "alias/db-master-key"
  target_key_id = aws_kms_key.db_creds_key.id
}

# -----------------------------------------------------------------------------
# 2. Secrets Manager Secret
# -----------------------------------------------------------------------------
# Generate a secure random password
resource "random_password" "master_password" {
  length  = 32
  special = true
}

# Create the secret encrypted with the designated KMS key
resource "aws_secretsmanager_secret" "db_master_secret" {
  name                    = "rds/master-credentials"
  description             = "Master credentials for the primary RDS instance"
  kms_key_id              = aws_kms_key.db_creds_key.id
  recovery_window_in_days = 0
}

# Store the initial credentials in the secret
resource "aws_secretsmanager_secret_version" "db_master_secret_version" {
  secret_id = aws_secretsmanager_secret.db_master_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.master_password.result
  })
}

# -----------------------------------------------------------------------------
# 3. Networking (VPC, Subnets, Security Group)
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "db-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "db_subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = {
    Name = "db-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.db_subnets[*].id
  tags = {
    Name = "main-db-subnet-group"
  }
}

resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Security group for the database"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# -----------------------------------------------------------------------------
# 4. AWS Database (RDS)
# -----------------------------------------------------------------------------
resource "aws_db_instance" "main" {
  identifier             = "secure-database"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true

  db_name                = "appdb"
  username               = "admin"
  password               = random_password.master_password.result # Required for initial creation

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  skip_final_snapshot    = true
  publicly_accessible    = false

  # Integrating with Secrets Manager
  master_user_secret {
    name = aws_secretsmanager_secret.db_master_secret.name
  }
}

