    Name = "ExampleEFS"
  }
}

resource "aws_efs_file_system_policy" "example" {
  file_system_id = aws_efs_file_system.example.id

  # Bypass the policy lockout safety check. 
  # This prevents the policy from locking out the account owner.
  # In production, ensure the policy allows the account owner to modify the file system.
  bypass_policy_lockout_safety_check = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "ExampleStatement"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = aws_efs_file_system.example.arn
        Condition = {
          Bool = {
            "aws:SecureTransport" = "true"
          }
        }
      }
    ]
  })
}

