provider "aws" {
  region = "us-east-1"
}

# Variable to specify the chosen VPC ID
variable "vpc_id" {
  description = "The ID of the VPC to attach the DHCP options set to"
  type        = string
}

# VPC DHCP Options Set named "pike" using Google DNS
resource "aws_vpc_dhcp_options" "pike" {
  domain_name_servers = ["8.8.8.8", "8.8.4.4"]

  tags = {
    Name = "pike"
    permissions = "true"
  }
}

# Association of the DHCP options set to the chosen VPC
# Note: The aws_vpc_dhcp_options_association resource does not support tags in the AWS API/Terraform provider.
resource "aws_vpc_dhcp_options_association" "pike_association" {
  vpc_id          = var.vpc_id
  dhcp_options_id = aws_vpc_dhcp_options.pike.id
}

