provider "aws" {
  region = "us-east-1"
}

# Designated VPC (Created for context as none was provided)
resource "aws_vpc" "designated" {
  cidr_block = "10.0.0.0/16"
}

# DHCP Options Set called "pike" using Google's DNS
resource "aws_vpc_dhcp_options" "pike" {
  domain_name_servers = ["8.8.8.8", "8.8.4.4"]

  tags = {
    Name        = "pike"
    Permissions = "pike"
  }
}

# Association of the DHCP options set to the VPC
resource "aws_vpc_dhcp_options_association" "pike_assoc" {
  vpc_id          = aws_vpc.designated.id
  dhcp_options_id = aws_vpc_dhcp_options.pike.id

  tags = {
    Permissions = "pike"
  }
}

